const QUESTIONS_SECX_C1 = [
  {"id": 70101, "domain": 1, "level": 1, "question": "Which principle is the foundation of a zero trust architecture?", "options": ["Trust is never granted implicitly and must be continuously verified for every request", "Internal network traffic is trusted once a device passes perimeter firewall inspection", "Users authenticate once at login and retain broad access for the session duration", "Security controls focus mainly on hardening the network perimeter against outsiders"], "correct": 0, "explanation": "Zero trust eliminates implicit trust; perimeter-only and one-time authentication models assume internal trust, which zero trust rejects."},
  {"id": 70102, "domain": 1, "level": 1, "question": "What does ZTNA primarily replace in a modern remote access design?", "options": ["Endpoint antivirus agents that scan files for known malware signatures on the host", "Traditional VPNs that grant broad network-level access after a single authentication", "Email gateways that filter inbound phishing and spam before delivery to user inboxes", "Backup systems that replicate data to an offsite disaster recovery facility nightly"], "correct": 1, "explanation": "ZTNA provides per-application access rather than network access; antivirus, email gateways, and backups address unrelated functions."},
  {"id": 70103, "domain": 1, "level": 3, "question": "In zero trust, what is the role of the policy decision point (PDP)?", "options": ["It physically routes packets between segmented VLANs at wire speed in the data plane in this enterprise environment", "It stores encrypted backups of policy documents for later compliance auditing needs", "It evaluates signals and context to decide whether an access request should be allowed", "It terminates TLS sessions and caches static web content closer to the end users"], "correct": 2, "explanation": "The PDP makes access decisions from context and policy; the other choices describe routing, backup, and caching, not decisions."},
  {"id": 70104, "domain": 1, "level": 3, "question": "Why is microsegmentation central to zero trust east-west traffic control?", "options": ["It increases raw network throughput by removing all inspection from internal trunk links in this enterprise environment", "It consolidates every internal traffic flow through a single chokepoint for simplicity", "It eliminates the need for any identity verification on north-south traffic flows", "It restricts lateral movement by enforcing fine-grained policy between individual workloads"], "correct": 3, "explanation": "Microsegmentation limits lateral movement with granular policy; it does not boost throughput, centralize traffic, or remove identity."},
  {"id": 70105, "domain": 1, "level": 1, "question": "Which signal is LEAST likely used by a zero trust engine for continuous evaluation?", "options": ["The aesthetic color theme configured in the user's personal desktop wallpaper preferences", "Device posture such as patch level, disk encryption status, and EDR agent health checks", "User identity together with the classification sensitivity of the resource being requested", "Network location, geovelocity, and unusual time-of-day patterns for the active session"], "correct": 0, "explanation": "Wallpaper theme is irrelevant to risk; device posture, identity, resource sensitivity, and location are standard trust signals."},
  {"id": 70106, "domain": 1, "level": 1, "question": "Which combination best describes SASE?", "options": ["A single on-premises appliance that backhauls all branch traffic to the headquarters site", "Convergence of WAN networking such as SD-WAN with cloud-delivered security services together", "An endpoint-only agent that performs full disk encryption and local malware scanning tasks in this enterprise environment", "A hardware load balancer that distributes inbound web requests across a server pool evenly"], "correct": 1, "explanation": "SASE converges networking (SD-WAN) and security as a cloud service; the distractors describe legacy backhaul, endpoint, and balancing."},
  {"id": 70107, "domain": 1, "level": 1, "question": "What core capabilities make up Security Service Edge (SSE)?", "options": ["DHCP, DNS, and NTP services hosted redundantly within an on-premises corporate datacenter", "RAID arrays, tape libraries, and snapshots forming a tiered enterprise storage backend", "SWG, CASB, and ZTNA delivered together from a single cloud-native security platform", "BGP, OSPF, and MPLS protocols used to interconnect geographically remote branch offices"], "correct": 2, "explanation": "SSE bundles SWG, CASB, and ZTNA; the distractors list infrastructure, storage, and routing protocols unrelated to SSE."},
  {"id": 70108, "domain": 1, "level": 1, "question": "A key driver for adopting SASE over traditional hub-and-spoke is that it:", "options": ["Forces all cloud-bound traffic back to one central datacenter for mandatory inspection", "Removes the need for any identity or device posture checks on user access sessions", "Eliminates encryption requirements because traffic never leaves the cloud provider edge", "Reduces latency by inspecting traffic at distributed edge points of presence near users"], "correct": 3, "explanation": "SASE inspects near the user at distributed PoPs, cutting latency; backhauling, dropping identity, and skipping encryption are wrong."},
  {"id": 70109, "domain": 1, "level": 1, "question": "In the shared responsibility model for IaaS, the customer is typically responsible for:", "options": ["Securing the guest operating system, the applications, and the data that they deploy", "Maintaining the physical security of the cloud provider's regional datacenter buildings", "Patching the underlying hypervisor that hosts all of the tenant virtual machine instances", "Managing the provider's core network backbone and the firmware on its edge routers"], "correct": 0, "explanation": "In IaaS the customer secures OS, apps, and data; the provider owns physical, hypervisor, and backbone layers."},
  {"id": 70110, "domain": 1, "level": 1, "question": "Which service model gives the customer the LEAST security responsibility?", "options": ["IaaS, where the customer manages the OS, middleware, runtime, and the applications", "SaaS, where the provider manages the application, the runtime, and all infrastructure", "On-premises hosting, where the organization owns and secures the entire technology stack", "PaaS, where the customer still manages the application code and its own configuration"], "correct": 1, "explanation": "SaaS shifts the most responsibility to the provider; IaaS, on-prem, and PaaS leave more of the stack to the customer."},
  {"id": 70111, "domain": 1, "level": 1, "question": "What is the primary function of a CASB?", "options": ["Encrypting all data at rest on local employee laptops and attached removable drives", "Routing branch office WAN traffic over the most cost-effective available carrier link", "Enforcing visibility, compliance, and data security policy for cloud service usage", "Scanning container images for known vulnerabilities before they reach the registry"], "correct": 2, "explanation": "A CASB governs cloud service usage and data policy; disk encryption, WAN routing, and image scanning are other tools."},
  {"id": 70112, "domain": 1, "level": 1, "question": "Cloud Security Posture Management (CSPM) is designed primarily to:", "options": ["Inspect running container processes for malicious in-memory behavior during execution in this enterprise environment", "Terminate user VPN tunnels and enforce split-tunneling policy at the network edge", "Provide a web application firewall in front of all public-facing API endpoints", "Detect misconfigurations and compliance drift across the cloud provider control planes"], "correct": 3, "explanation": "CSPM finds cloud misconfigurations and drift; runtime inspection is CWPP, and the others are VPN and WAF functions."},
  {"id": 70113, "domain": 1, "level": 1, "question": "A Cloud Workload Protection Platform (CWPP) focuses on:", "options": ["Protecting workloads such as virtual machines, containers, and serverless at runtime", "Discovering shadow IT SaaS applications used by employees without any approval", "Managing certificate issuance and revocation across the enterprise public key infrastructure", "Aggregating logs from network devices into a central SIEM for correlation and alerting"], "correct": 0, "explanation": "CWPP secures workloads at runtime; SaaS discovery is CASB, and the others are PKI and SIEM functions."},
  {"id": 70114, "domain": 1, "level": 3, "question": "CNAPP consolidates which capabilities into one platform?", "options": ["DLP, email filtering, and endpoint EDR for traditional on-premises office environments", "CSPM, CWPP, CIEM, and IaC scanning across the full cloud-native application lifecycle", "Physical badge access, CCTV monitoring, and HVAC alerting for datacenter facilities", "Tape backup, cross-region replication, and bare-metal restore for disaster recovery"], "correct": 1, "explanation": "CNAPP unifies CSPM, CWPP, CIEM, and IaC scanning; the distractors mix unrelated endpoint, physical, and backup tools."},
  {"id": 70115, "domain": 1, "level": 3, "question": "Why is CIEM increasingly important in multi-cloud environments?", "options": ["It accelerates large file transfers between regions using dedicated provider fiber links", "It provides a managed relational database service with automatic failover read replicas", "It manages and right-sizes the explosion of cloud entitlements and excessive permissions", "It renders cost dashboards that visualize monthly cloud spending by individual department"], "correct": 2, "explanation": "CIEM governs excessive cloud entitlements; the distractors describe transfer, database, and cost-reporting services."},
  {"id": 70116, "domain": 1, "level": 3, "question": "Which approach best secures east-west traffic between microservices?", "options": ["A single shared administrator credential reused by every service for operational ease", "Disabling all internal request logging to reduce performance overhead at large scale", "Exposing each microservice directly to the public internet for deployment simplicity", "A service mesh enforcing mutual TLS and policy between individual service instances"], "correct": 3, "explanation": "A service mesh provides mTLS and policy between services; shared creds, disabled logging, and public exposure weaken security."},
  {"id": 70117, "domain": 1, "level": 1, "question": "An API gateway contributes to security architecture primarily by:", "options": ["Centralizing authentication, rate limiting, and request validation for backend APIs", "Storing the only authoritative copy of the application's production database records", "Compiling application source code into optimized binaries during the build pipeline", "Provisioning new virtual machines on demand for autoscaling background worker pools"], "correct": 0, "explanation": "An API gateway centralizes authN, throttling, and validation; it is not a database, compiler, or VM provisioner."},
  {"id": 70118, "domain": 1, "level": 3, "question": "What is a unique security consideration for serverless functions?", "options": ["Patching the long-lived guest operating system that the function continuously runs on", "Minimizing function permissions and carefully managing event-source trust boundaries", "Maintaining persistent local disk encryption keys across many separate executions", "Configuring static firewall rules tied to a single fixed function IP address always"], "correct": 1, "explanation": "Serverless needs least-privilege roles and trusted event sources; there is no long-lived OS, persistent disk, or fixed IP."},
  {"id": 70119, "domain": 1, "level": 3, "question": "Broken object level authorization (BOLA) in APIs is best mitigated by:", "options": ["Returning verbose stack traces so that clients can debug their failed requests easily", "Relying on obscure, hard-to-guess object identifiers as the only access control measure", "Verifying that the authenticated caller is authorized for each object that is accessed", "Trusting client-supplied role claims without any server-side revalidation of permissions"], "correct": 2, "explanation": "BOLA requires per-object authorization checks; verbose errors, obscurity, and trusting client claims do not enforce authorization."},
  {"id": 70120, "domain": 1, "level": 3, "question": "Which control most directly reduces container breakout risk?", "options": ["Granting every container privileged mode to simplify mounting of shared host volumes", "Sharing the host PID and network namespaces across all of the running containers", "Disabling image signing so that any pulled image can be run quickly without checks", "Running containers as non-root with seccomp profiles and dropped Linux capabilities"], "correct": 3, "explanation": "Non-root, seccomp, and dropped capabilities limit breakout; privileged mode, shared namespaces, and unsigned images add risk."},
  {"id": 70121, "domain": 1, "level": 1, "question": "In Kubernetes, what does a NetworkPolicy enforce?", "options": ["Allowed network communication between pods and namespaces at network layers three and four", "The CPU and memory resource limits that a pod's containers may consume while running", "Which container registries are considered trusted sources for pulling pod images from in this enterprise environment", "The encryption algorithm used to protect cluster secrets stored within etcd at rest"], "correct": 0, "explanation": "NetworkPolicy controls pod-to-pod connectivity; resource limits, image trust, and etcd encryption are configured elsewhere."},
  {"id": 70122, "domain": 1, "level": 1, "question": "Why should Kubernetes secrets be encrypted at rest in etcd?", "options": ["Encryption at rest fully replaces the need for any RBAC controls on the secret objects", "By default etcd may store secret values base64-encoded but not actually encrypted at all", "It guarantees that secrets can never be read by any legitimate cluster administrator", "It automatically rotates every application credential on a fixed predetermined schedule in this enterprise environment"], "correct": 1, "explanation": "Base64 is encoding, not encryption, so at-rest encryption is needed; it does not replace RBAC, hide secrets, or rotate creds."},
  {"id": 70123, "domain": 1, "level": 1, "question": "A pod security standard set to 'restricted' primarily aims to:", "options": ["Increase pod scheduling speed by skipping the cluster admission controller checks entirely", "Allow all host path volume mounts so that pods can read any file on the worker node", "Prevent privilege escalation and enforce hardened pod security defaults across workloads", "Disable resource quotas so that workloads can scale freely without any imposed limits"], "correct": 2, "explanation": "The restricted profile blocks escalation and hardens pods; the distractors describe behaviors that weaken or bypass security."},
  {"id": 70124, "domain": 1, "level": 1, "question": "Hypervisor-based virtualization introduces which distinct risk?", "options": ["Loss of all stored data whenever a single guest VM is gracefully and cleanly shut down", "Inability to encrypt any virtual disk image because of inherent hypervisor limitations", "Mandatory exposure of every virtual machine directly to the public internet by default", "VM escape attacks that breach the isolation between the guests and the underlying host"], "correct": 3, "explanation": "VM escape breaches guest isolation; graceful shutdown, encryption limits, and forced exposure are not inherent hypervisor risks."},
  {"id": 70125, "domain": 1, "level": 1, "question": "Scanning Infrastructure as Code before deployment helps to:", "options": ["Catch insecure configurations like open security groups well before any provisioning", "Encrypt the network traffic between the deployed application tiers automatically at runtime", "Replace entirely the need for runtime monitoring of the provisioned cloud environment", "Guarantee that no zero-day vulnerabilities exist in any package that is later deployed"], "correct": 0, "explanation": "IaC scanning catches misconfigurations pre-deploy; it does not encrypt traffic, replace runtime monitoring, or eliminate zero-days."},
  {"id": 70126, "domain": 1, "level": 3, "question": "A major benefit of immutable infrastructure for security is that:", "options": ["Administrators can freely make undocumented changes to live production hosts as needed", "Servers are replaced rather than patched in place, which reduces configuration drift", "Logging can be disabled entirely because immutable systems never change once deployed", "It removes the need to scan images since deployed instances never differ from one another"], "correct": 1, "explanation": "Immutability reduces drift by replacing instances; the distractors describe drift-inducing or oversight-removing practices."},
  {"id": 70127, "domain": 1, "level": 1, "question": "Storing secrets directly in Terraform state files is risky because:", "options": ["Terraform automatically encrypts state with a per-user key that cannot ever be shared in this enterprise environment", "State files are deleted immediately after each apply, which would lose those secrets", "State files often contain sensitive values in plaintext and may be shared quite widely", "Secrets in state are only ever accessible from the original author's personal laptop"], "correct": 2, "explanation": "State can hold plaintext secrets and is widely accessible; it is not auto-encrypted, auto-deleted, or limited to one laptop."},
  {"id": 70128, "domain": 1, "level": 1, "question": "The principal security benefit of network segmentation is:", "options": ["Eliminating the requirement for any endpoint detection on the segmented host machines", "Increasing the aggregate bandwidth that is available to every connected client device", "Removing the requirement to patch operating systems within the isolated network segments", "Containing breaches and limiting an attacker's lateral movement across the trust zones"], "correct": 3, "explanation": "Segmentation contains breaches and limits lateral movement; it does not remove endpoint controls, add bandwidth, or remove patching."},
  {"id": 70129, "domain": 1, "level": 3, "question": "Microsegmentation differs from traditional VLAN segmentation in that it:", "options": ["Applies fine-grained, identity-aware policy down to the level of individual workloads", "Operates only at the physical switch port level using static manual cabling assignments", "Requires a completely separate physical network for each application in the datacenter", "Can only segment traffic between different geographic regions rather than between hosts"], "correct": 0, "explanation": "Microsegmentation is workload-level and identity-aware; VLANs are coarser, and the other options misstate its capabilities."},
  {"id": 70130, "domain": 1, "level": 3, "question": "Placing OT systems on an isolated segment with a unidirectional gateway:", "options": ["Permits full bidirectional remote administration of every connected OT controller device", "Allows data to flow out for monitoring while blocking inbound attack paths into the zone", "Increases OT exposure by bridging it directly to the broader corporate Windows domain", "Removes the need to monitor any of the traffic crossing the defined OT trust boundary"], "correct": 1, "explanation": "A data diode lets telemetry out while blocking inbound traffic; the distractors describe exposure-increasing or oversight-removing setups."},
  {"id": 70131, "domain": 1, "level": 1, "question": "In a SAML federation, the identity provider (IdP) is responsible for:", "options": ["Hosting the actual application that the user ultimately wants to access and then use", "Storing the encrypted backups of the service provider's full customer record database in this enterprise environment", "Authenticating the user and issuing a signed assertion to the relying service provider", "Routing the user's network packets to the nearest available regional data center node"], "correct": 2, "explanation": "The IdP authenticates and issues assertions; the SP hosts the app, and the distractors describe unrelated backup and routing roles."},
  {"id": 70132, "domain": 1, "level": 1, "question": "OIDC is best described as:", "options": ["A symmetric encryption protocol used to protect stored data at rest within databases", "A network segmentation standard for isolating untrusted IoT devices from core servers", "A backup scheduling framework for replicating organizational data across cloud regions", "An identity layer built on top of OAuth 2.0 that adds a verifiable ID token for users"], "correct": 3, "explanation": "OIDC adds an identity layer (ID token) atop OAuth 2.0; the distractors describe encryption, segmentation, and backup."},
  {"id": 70133, "domain": 1, "level": 2, "question": "What is the purpose of SCIM in identity architecture?", "options": ["Automating the provisioning and deprovisioning of user accounts across many systems", "Encrypting SAML assertions while in transit between the IdP and the service provider", "Generating time-based one-time passcodes for multifactor authentication challenges", "Inspecting east-west traffic between microservices for any access policy violations"], "correct": 0, "explanation": "SCIM automates account lifecycle provisioning; it is not an encryption, OTP, or traffic-inspection mechanism."},
  {"id": 70134, "domain": 1, "level": 2, "question": "A federated SSO design reduces risk primarily by:", "options": ["Requiring users to maintain a unique strong password for every single application used in this enterprise environment", "Centralizing authentication so that credentials are not stored at each separate application", "Eliminating entirely the need for any multifactor authentication on sensitive systems", "Allowing each application to independently issue its own unverified trust assertions"], "correct": 1, "explanation": "Federation centralizes authentication and reduces credential sprawl; the distractors describe password sprawl or weakened trust."},
  {"id": 70135, "domain": 1, "level": 3, "question": "Why might an organization deploy a separate IdP for B2B partner access?", "options": ["Because partners must always share exactly the same accounts as the internal staff do", "To deliberately avoid logging any partner authentication events for vague privacy reasons", "To isolate partner trust and apply tailored policies without affecting internal employees", "Because federation protocols simply cannot support more than one relying party at a time"], "correct": 2, "explanation": "A separate partner IdP isolates trust and policy; the distractors describe poor practices or false protocol limits."},
  {"id": 70136, "domain": 1, "level": 3, "question": "Token-based authentication improves on session cookies in distributed systems by:", "options": ["Requiring every microservice to share one central in-memory session table for lookups", "Storing the user's plaintext account password inside the token itself for faster reuse in this enterprise environment", "Preventing tokens from ever expiring so that users never need to re-authenticate again", "Allowing stateless verification of claims without any server-side session storage required"], "correct": 3, "explanation": "Tokens enable stateless claim verification; shared session tables, embedded passwords, and non-expiring tokens are insecure."},
  {"id": 70137, "domain": 1, "level": 2, "question": "SPF, DKIM, and DMARC together primarily protect against:", "options": ["Email spoofing by validating sender authenticity and the alignment of the domains used", "Malware that is hidden inside encrypted ZIP archive attachments on inbound messages", "Denial-of-service floods that are aimed at the organization's mail transfer agent servers", "Eavesdropping on the email message content as it traverses the open public internet"], "correct": 0, "explanation": "SPF/DKIM/DMARC authenticate senders to stop spoofing; they do not scan malware, block DoS, or encrypt content in transit."},
  {"id": 70138, "domain": 1, "level": 2, "question": "DNSSEC adds security to DNS by:", "options": ["Encrypting all DNS query traffic so that it is hidden from any passive network observers", "Cryptographically signing records to ensure their integrity and their authenticity", "Caching authoritative responses for longer to reduce the load on the name server fleet", "Blocking client access to domains that currently appear on a known malware blocklist"], "correct": 1, "explanation": "DNSSEC signs records for integrity and authenticity; encryption is DoH/DoT, and the distractors describe caching and filtering."},
  {"id": 70139, "domain": 1, "level": 1, "question": "A web application firewall (WAF) is best positioned to mitigate:", "options": ["Physical theft of backup tapes taken from an offsite cold storage holding facility", "Misconfigured IAM roles that grant excessive entitlements to cloud service principals", "Application-layer attacks such as SQL injection and reflected cross-site scripting", "Lateral movement between two virtual machines hosted on the same physical hypervisor"], "correct": 2, "explanation": "A WAF blocks layer-7 attacks like SQLi and XSS; the distractors involve physical, IAM, and hypervisor concerns outside its scope."},
  {"id": 70140, "domain": 1, "level": 2, "question": "DNS sinkholing is used in security architecture to:", "options": ["Speed up legitimate DNS resolution by pre-fetching the most popular requested domains in this enterprise environment", "Encrypt DNS queries between the recursive resolver and the authoritative name servers", "Load balance DNS query traffic evenly across multiple separate resolver instances run", "Redirect malicious domain lookups to a controlled address for containment and analysis"], "correct": 3, "explanation": "Sinkholing redirects malicious lookups for containment and analysis; the distractors describe performance, encryption, and balancing."},
  {"id": 70141, "domain": 1, "level": 2, "question": "A common challenge securing legacy ICS/SCADA environments is that:", "options": ["Many devices lack patching and authentication and run fragile legacy industrial protocols", "All of the controllers natively support modern TLS and certificate-based mutual authentication", "They are typically fully isolated and never require any form of network connectivity at all", "Their firmware updates are pushed out automatically every single day by the equipment vendor"], "correct": 0, "explanation": "Legacy ICS often lacks patching and strong auth; the distractors overstate modern security capabilities these systems rarely have."},
  {"id": 70142, "domain": 1, "level": 2, "question": "The Purdue Model is used in OT architecture to:", "options": ["Encrypt all of the sensor telemetry using one standardized symmetric block cipher always", "Define hierarchical levels that segment industrial control systems from enterprise IT", "Provision cloud virtual machines on demand for heavy industrial analytics workloads", "Authenticate users with biometric factors at the physical plant entrance security gate"], "correct": 1, "explanation": "The Purdue Model defines segmentation levels for ICS; it is not an encryption, provisioning, or physical access scheme."},
  {"id": 70143, "domain": 1, "level": 1, "question": "Why is network segmentation especially critical for IoT deployments?", "options": ["IoT devices generate so little network traffic that segmentation carries no real cost", "Segmentation causes IoT devices to automatically receive vendor security patches faster", "Many IoT devices are weakly secured and can easily become footholds for attackers", "IoT devices always ship with strong unique default credentials that fully resist attack"], "correct": 2, "explanation": "Weak IoT devices need isolation to limit blast radius; segmentation neither patches devices nor are defaults typically strong."},
  {"id": 70144, "domain": 1, "level": 3, "question": "Securing embedded device firmware is best supported by:", "options": ["Disabling all cryptographic functions on the device to conserve its very limited battery power in this enterprise environment", "Hardcoding a single shared symmetric key into every unit that is shipped to all customers", "Allowing unsigned firmware images so that field technicians can apply patches more quickly", "A hardware root of trust that enables verified secure boot of cryptographically signed firmware"], "correct": 3, "explanation": "A hardware root of trust with secure boot ensures firmware integrity; disabling crypto, shared keys, and unsigned firmware are insecure."},
  {"id": 70145, "domain": 1, "level": 2, "question": "The difference between MDM and MAM is that MAM:", "options": ["Manages and secures specific applications and their data rather than the entire device", "Always wipes the entire personal device whenever an employee leaves the organization", "Requires the organization to physically own every single device that it intends to secure", "Can only ever be applied to corporate-owned desktops and never to personal mobile phones"], "correct": 0, "explanation": "MAM secures specific apps and data, ideal for BYOD; MDM manages the whole device, and the distractors misstate MAM's scope."},
  {"id": 70146, "domain": 1, "level": 2, "question": "In a BYOD environment, containerization on mobile devices helps by:", "options": ["Granting the IT team full remote control over the user's personal photos and private messages", "Separating corporate data into a managed container isolated from the user's personal data", "Disabling the device camera and microphone permanently for every application that is installed", "Forcing the user to perform a full factory reset of the device before each corporate login"], "correct": 1, "explanation": "Containerization isolates corporate data from personal; the distractors describe overreaching or impractical controls."},
  {"id": 70147, "domain": 1, "level": 2, "question": "An active-active architecture improves resilience by:", "options": ["Keeping a cold standby site fully powered off until a complete disaster is formally declared", "Storing the only authoritative production data copy at a single primary physical location", "Running multiple sites that simultaneously serve live traffic and can absorb a failover", "Requiring manual DNS record edits before any traffic can shift between the available sites"], "correct": 2, "explanation": "Active-active sites share live load and absorb failures; cold standby, single copies, and manual cutover offer weaker resilience."},
  {"id": 70148, "domain": 1, "level": 1, "question": "RTO and RPO differ in that RPO defines:", "options": ["The maximum acceptable length of time to restore a service after an unexpected outage in this enterprise environment", "The total number of concurrent users that a given system can support at its peak load", "The minimum encryption strength that is required for data replicated to a backup site", "The maximum acceptable amount of data loss as measured backward in time from an incident"], "correct": 3, "explanation": "RPO is tolerable data loss in time; RTO is restore time, and the distractors describe capacity and encryption unrelated to either."},
  {"id": 70149, "domain": 1, "level": 1, "question": "A key reason to follow the 3-2-1 backup strategy is to:", "options": ["Keep multiple copies on different media with at least one stored offsite for resilience", "Ensure that backups are never encrypted so that they restore back as fast as possible", "Store all of the copies on the same disk array to simplify the restoration procedures", "Replace the need for testing restores because keeping three copies always works reliably"], "correct": 0, "explanation": "3-2-1 ensures redundancy and offsite protection; the distractors weaken backups or wrongly skip restore testing."},
  {"id": 70150, "domain": 1, "level": 2, "question": "Designing for graceful degradation means a system should:", "options": ["Shut itself down entirely the moment any single component reports a recoverable error", "Continue providing its core functions with reduced capability during a partial failure", "Hide all failures from users by silently returning stale or incorrect data to requests", "Require a full manual restart whenever the load exceeds normal operating thresholds"], "correct": 1, "explanation": "Graceful degradation preserves core functions under partial failure; the distractors describe brittle or deceptive behavior."},
  {"id": 70151, "domain": 1, "level": 2, "question": "A honeypot is deployed in an architecture primarily to:", "options": ["Serve as the primary production database for processing real customer transactions", "Accelerate legitimate user traffic by routing it through dedicated edge cache nodes", "Lure and detect attackers by presenting a convincing decoy system of apparent value", "Replace the organization's entire intrusion prevention system with a single decoy"], "correct": 2, "explanation": "A honeypot detects and studies attackers via a decoy; it is not a production database, cache, or IPS replacement."},
  {"id": 70152, "domain": 1, "level": 3, "question": "How does a honeytoken differ from a honeypot?", "options": ["A honeytoken is a hardened production server that is intentionally exposed to the internet", "A honeytoken physically isolates the OT networks from the corporate IT systems entirely", "A honeytoken encrypts backups before they are written out to the offsite cold storage", "A honeytoken is decoy data whose use signals unauthorized access or attempted theft"], "correct": 3, "explanation": "A honeytoken is decoy data triggering alerts on use; the distractors describe servers, segmentation, and encryption."},
  {"id": 70153, "domain": 1, "level": 2, "question": "External attack surface management (EASM) primarily focuses on:", "options": ["Discovering and monitoring internet-facing assets that an external adversary can see", "Encrypting the internal database tables that hold regulated customer payment records", "Provisioning developer laptops with one standardized hardened operating system image", "Negotiating bandwidth contracts with the various regional internet service providers"], "correct": 0, "explanation": "EASM discovers and monitors internet-facing assets; the distractors describe encryption, provisioning, and procurement."},
  {"id": 70154, "domain": 1, "level": 1, "question": "Reducing attack surface through least functionality means:", "options": ["Installing every available software package upfront in case it might be needed later on", "Disabling the unnecessary services, open ports, and unused features on each system", "Opening all firewall ports in advance to simplify any future application deployments", "Granting all users full administrative rights in order to avoid future support tickets"], "correct": 1, "explanation": "Least functionality removes unneeded services and features; the distractors all expand rather than reduce attack surface."},
  {"id": 70155, "domain": 1, "level": 2, "question": "Shift-left security in DevSecOps means:", "options": ["Deferring all of the security testing until just before the final production release date", "Moving security responsibility entirely onto a separate downstream operations team only", "Integrating security testing and review earlier within the software development lifecycle", "Removing the automated tests entirely to accelerate the continuous delivery pipeline speed"], "correct": 2, "explanation": "Shift-left moves testing earlier; the distractors describe deferring, siloing, or removing security activities."},
  {"id": 70156, "domain": 1, "level": 2, "question": "SAST and DAST differ in that DAST:", "options": ["Analyzes the application source code statically before it has ever been compiled at all", "Only inspects the third-party open-source dependencies for any known published CVEs", "Encrypts the produced build artifacts before they are stored in the artifact registry", "Tests a running application from the outside without any access to its source code"], "correct": 3, "explanation": "DAST tests running apps externally; SAST analyzes source, SCA scans dependencies, and the last option is unrelated to testing."},
  {"id": 70157, "domain": 1, "level": 2, "question": "Software composition analysis (SCA) is used to:", "options": ["Identify vulnerable and outdated open-source components within an application's dependencies", "Encrypt application traffic flowing between the front-end and the back-end service tiers", "Perform automated fuzz testing against the application's externally exposed API endpoints in this enterprise environment", "Manage the issuance of TLS certificates for the organization's production web servers"], "correct": 0, "explanation": "SCA finds vulnerable open-source dependencies; encryption, fuzzing, and certificate issuance are different functions."},
  {"id": 70158, "domain": 1, "level": 3, "question": "Signing build artifacts in a CI/CD pipeline primarily provides:", "options": ["Faster overall compilation by caching the previously built object files on the local disk", "Integrity and provenance assurance that the artifacts were not tampered with after build", "Automatic remediation of every single vulnerability that was found during the build process", "Guaranteed backward compatibility with all prior released versions of the application code"], "correct": 1, "explanation": "Artifact signing assures integrity and provenance; it does not speed builds, fix vulnerabilities, or ensure compatibility."},
  {"id": 70159, "domain": 1, "level": 1, "question": "Defense in depth is the principle of:", "options": ["Relying on one very strong perimeter firewall as the only safeguard for the network", "Trusting all of the internal systems implicitly once a user is inside the network edge", "Layering multiple independent controls so that no single failure becomes catastrophic", "Removing redundant controls in order to simplify the overall security architecture design"], "correct": 2, "explanation": "Defense in depth layers controls; single-control reliance, implicit trust, and removing redundancy contradict it."},
  {"id": 70160, "domain": 1, "level": 1, "question": "The principle of least privilege requires that:", "options": ["All users share a single common administrative account purely for operational efficiency", "Permissions are granted broadly upfront and are only revoked after a security incident occurs", "Periodic access reviews become unnecessary once the initial permissions have been assigned", "Subjects receive only the minimum access that is necessary to perform their assigned tasks"], "correct": 3, "explanation": "Least privilege grants only necessary access; shared admin, broad grants, and skipping reviews all violate it."},
  {"id": 70161, "domain": 1, "level": 2, "question": "Fail-secure (fail-closed) design means that when a control fails it:", "options": ["Denies access by default in order to preserve security over continued availability", "Grants access by default in order to preserve availability over continued security", "Randomly chooses to either allow or deny each individual request that happens to arrive", "Silently logs the failure while continuing to permit all of the inbound traffic regardless"], "correct": 0, "explanation": "Fail-secure denies access on failure; fail-open grants it, and the distractors describe nondeterministic or unsafe behavior."},
  {"id": 70162, "domain": 1, "level": 2, "question": "Separation of duties is implemented to:", "options": ["Allow one administrator to both request and then approve all of the major system changes in this enterprise environment", "Prevent any single individual from completing a sensitive business process entirely alone", "Reduce headcount by consolidating several conflicting roles into one combined position", "Eliminate the need for any audit logging since the duties are already cleanly divided"], "correct": 1, "explanation": "Separation of duties splits sensitive tasks among people; the distractors recombine duties or remove oversight."},
  {"id": 70163, "domain": 1, "level": 1, "question": "Secure defaults as a design principle means:", "options": ["Systems ship fully open so that users can then lock down only what they decide they need", "Security features are turned off by default in order to maximize the initial ease of use", "Systems ship pre-configured for the most secure setting right out of the box by default", "Default vendor credentials remain unchanged in order to simplify the initial deployment"], "correct": 2, "explanation": "Secure defaults ship locked down; open defaults, disabled features, and unchanged credentials are insecure."},
  {"id": 70164, "domain": 1, "level": 2, "question": "In a PKI, the role of the registration authority (RA) is to:", "options": ["Physically host the web application that later presents the certificate to its clients", "Encrypt all of the data at rest within the certificate authority's backend database store", "Distribute symmetric session keys directly to every single endpoint on the network", "Verify the identity of the requesters before a certificate is issued by the authority"], "correct": 3, "explanation": "The RA validates identity before issuance; it does not host apps, encrypt CA storage, or distribute symmetric keys."},
  {"id": 70165, "domain": 1, "level": 3, "question": "Certificate pinning in an application architecture helps prevent:", "options": ["Man-in-the-middle attacks that use fraudulent or otherwise unexpected certificates", "SQL injection attacks aimed at the application's backend relational database tables", "Brute-force password guessing attempts against the public user login endpoint", "Excessive cloud entitlements that are mistakenly granted to service principals"], "correct": 0, "explanation": "Pinning blocks MITM via rogue certs; SQLi, brute force, and entitlement sprawl are unrelated to certificate pinning."},
  {"id": 70166, "domain": 1, "level": 2, "question": "An HSM is used in cryptographic architecture to:", "options": ["Serve cached static web content from the network edge to geographically distant users in this enterprise environment", "Generate, store, and protect cryptographic keys within tamper-resistant secure hardware", "Aggregate and correlate security event logs from many different sources centrally", "Provide a virtual private network tunnel for remote employees connecting from home"], "correct": 1, "explanation": "An HSM protects keys in tamper-resistant hardware; the distractors describe CDN, SIEM, and VPN functions."},
  {"id": 70167, "domain": 1, "level": 3, "question": "Crypto-agility in architecture refers to the ability to:", "options": ["Encrypt data far faster by deliberately using shorter and weaker keys under heavy load", "Permanently lock the system to a single fixed algorithm that was chosen at launch time", "Swap cryptographic algorithms and keys without requiring a major full system redesign", "Avoid all key rotation entirely so as to maintain stable long-lived shared secrets"], "correct": 2, "explanation": "Crypto-agility enables swapping algorithms and keys easily; the distractors weaken crypto or prevent adaptation."},
  {"id": 70168, "domain": 1, "level": 3, "question": "Perfect forward secrecy ensures that:", "options": ["A single static key is used to encrypt all of the sessions purely for performance gains", "Session keys are stored indefinitely so that traffic can be conveniently decrypted later", "Certificates never need to be revoked at all once they have been initially issued out", "Compromise of a long-term private key does not expose any of the past session keys"], "correct": 3, "explanation": "PFS protects past sessions even if the long-term key leaks; static keys and stored session keys undermine that goal."},
  {"id": 70169, "domain": 1, "level": 2, "question": "In software-defined networking, separating the control and data planes allows:", "options": ["Centralized programmable policy while devices forward traffic per received instructions", "Each individual switch to independently invent its own incompatible routing rule set in this enterprise environment", "The complete elimination of any need for ongoing network monitoring or visibility", "Physical cabling to dynamically rewire itself without any direct human involvement"], "correct": 0, "explanation": "SDN centralizes control while the data plane forwards per policy; the distractors misstate SDN behavior."},
  {"id": 70170, "domain": 1, "level": 3, "question": "A security risk unique to SDN architectures is that:", "options": ["Each switch must be patched manually because there is no central controller in the design", "A compromised central controller could reprogram the entire network's forwarding behavior", "Traffic can never be inspected at all once it has entered the data plane forwarding path", "Policies simply cannot be changed at all after the network has been initially deployed"], "correct": 1, "explanation": "The centralized controller is a high-value single point; the distractors contradict SDN's centralized, programmable nature."},
  {"id": 70171, "domain": 1, "level": 1, "question": "Data classification in a security architecture primarily enables:", "options": ["Increasing overall storage capacity by compressing the lower-priority data records", "Eliminating the need for encryption on any information that has been classified at all", "Applying proportionate security controls based on the actual sensitivity of the data", "Granting all employees equal and unrestricted access to every category of stored data"], "correct": 2, "explanation": "Classification drives proportionate controls; it does not add storage, remove encryption, or flatten access."},
  {"id": 70172, "domain": 1, "level": 2, "question": "Tokenization protects sensitive data by:", "options": ["Encrypting it using a single key that is embedded directly within the application code", "Compressing it heavily in order to reduce the overall storage footprint of the database", "Hashing it so that the original cleartext value can be quickly recovered again later on", "Replacing it with a non-sensitive surrogate value while storing the original securely"], "correct": 3, "explanation": "Tokenization swaps data for a surrogate with a secure vault; embedded keys, compression, and reversible hashing are wrong."},
  {"id": 70173, "domain": 1, "level": 2, "question": "A data loss prevention (DLP) system in the architecture is positioned to:", "options": ["Detect and block the unauthorized movement of sensitive data across defined boundaries", "Accelerate slow database queries by indexing the most frequently accessed data tables", "Provision virtual desktop instances for remote contractors entirely on demand each day", "Rotate TLS certificates automatically across the organization's whole web server fleet"], "correct": 0, "explanation": "DLP detects and blocks sensitive data exfiltration; the distractors describe performance, provisioning, and certificate tasks."},
  {"id": 70174, "domain": 1, "level": 2, "question": "Mapping data flows during architecture design is valuable because it:", "options": ["Guarantees that no data will ever be intercepted while it is in transit anywhere at all", "Reveals where sensitive data is stored, processed, and transmitted so controls can apply", "Replaces entirely the need for any access control on the underlying data storage systems", "Automatically encrypts every single data flow without any additional configuration work"], "correct": 1, "explanation": "Data flow mapping reveals where to apply controls; it does not by itself guarantee, replace, or automate protection."},
  {"id": 70175, "domain": 1, "level": 2, "question": "A reverse proxy contributes to secure web architecture by:", "options": ["Storing the master copy of all of the user passwords in plaintext purely for fast lookups", "Serving as the sole authoritative DNS server for the entire organization's domain names", "Terminating TLS and shielding the backend servers behind a controlled single front end", "Replacing entirely the need for any authentication on the protected backend applications"], "correct": 2, "explanation": "A reverse proxy terminates TLS and shields backends; it is not a password store, DNS authority, or auth replacement."},
  {"id": 70176, "domain": 1, "level": 2, "question": "Bastion hosts (jump servers) are used to:", "options": ["Cache static website content in order to reduce page latency for global site visitors", "Store long-term archival backups of the organization's regulated financial records", "Distribute routine software updates out to the thousands of managed employee laptops", "Provide a hardened, closely monitored entry point for administering internal systems"], "correct": 3, "explanation": "A bastion is a hardened admin gateway; the distractors describe CDN, backup, and patch-distribution roles."},
  {"id": 70177, "domain": 1, "level": 1, "question": "A demilitarized zone (DMZ) in network architecture exists to:", "options": ["Host internet-facing services in a buffer zone that is separated from internal networks", "Store the organization's most sensitive data as close to the public internet as possible", "Provide unrestricted bidirectional access between the outside and the inside networks", "Replace the internal firewalls entirely because the DMZ already filters all of the traffic"], "correct": 0, "explanation": "A DMZ buffers public services from the internal network; the distractors describe insecure placements or removed controls."},
  {"id": 70178, "domain": 1, "level": 2, "question": "A key benefit of using a secrets management vault is:", "options": ["Embedding the credentials directly within the source code for the easiest developer access", "Centralized, fully audited storage together with dynamic, short-lived credential issuance", "Distributing the very same static password to every single service across the entire fleet", "Eliminating entirely the need to ever rotate or revoke any credential again in the future"], "correct": 1, "explanation": "A vault centralizes and dynamically issues short-lived secrets; the distractors describe insecure credential handling."},
  {"id": 70179, "domain": 1, "level": 3, "question": "Mutual TLS (mTLS) strengthens service-to-service communication by:", "options": ["Encrypting only the server side while leaving the connecting client fully unauthenticated", "Replacing the certificates entirely with shared static API keys purely for simplicity", "Authenticating both the client side and the server side using their own certificates", "Allowing any client to connect as long as it presents some valid username on the request"], "correct": 2, "explanation": "mTLS authenticates both ends with certs; one-sided auth, shared keys, and username-only access are weaker."},
  {"id": 70180, "domain": 1, "level": 2, "question": "A primary purpose of egress filtering is to:", "options": ["Increase the inbound bandwidth that is available for the public-facing applications run", "Disable all logging of the outbound connections in order to improve raw throughput", "Allow any internal host to freely reach any external destination without restriction", "Restrict outbound traffic in order to limit data exfiltration and command-and-control"], "correct": 3, "explanation": "Egress filtering limits outbound exfiltration and C2; the distractors describe bandwidth, logging removal, and open egress."},
  {"id": 70181, "domain": 1, "level": 3, "question": "Why is a single sign-on (SSO) outage considered a significant architectural risk?", "options": ["It can block access to many dependent applications at once as a single point of failure", "It only ever affects one single low-priority internal application and nothing else at all", "SSO inherently has no dependencies, so any outage cannot affect other connected systems", "Applications will automatically fall back to requiring no authentication during the outage"], "correct": 0, "explanation": "SSO is a single point of failure across many apps; the distractors understate impact or describe unsafe fallbacks."},
  {"id": 70182, "domain": 1, "level": 2, "question": "Conditional access policies in identity architecture evaluate:", "options": ["Only the username and the password while ignoring all of the other contextual signals", "Context such as device compliance, geographic location, and risk before granting access", "Solely the current time of day with no consideration at all of the device or the identity", "The physical color of the device that happens to be requesting the network connection"], "correct": 1, "explanation": "Conditional access weighs device, location, and risk; the distractors ignore key signals or use irrelevant criteria."},
  {"id": 70183, "domain": 1, "level": 3, "question": "A privileged access management (PAM) solution improves architecture by:", "options": ["Granting standing administrative rights to all of the users on a permanent ongoing basis", "Disabling session logging on privileged accounts in order to reduce overall storage costs", "Vaulting privileged credentials and brokering session access with continuous monitoring", "Sharing a single common root password across the entire administrative operations team"], "correct": 2, "explanation": "PAM vaults privileged creds and brokers monitored access; the distractors describe insecure standing or shared privilege."},
  {"id": 70184, "domain": 1, "level": 3, "question": "Just-in-time (JIT) access provisioning reduces risk by:", "options": ["Permanently assigning the admin roles upfront so that requests are never delayed at all", "Removing the need to authenticate at all before performing any privileged operation", "Allowing the elevated privileges to persist indefinitely after the task has been completed", "Granting elevated privileges only for a strictly limited window of time when truly needed"], "correct": 3, "explanation": "JIT grants time-bound privilege; permanent roles, skipped auth, and lingering privilege all increase risk."},
  {"id": 70185, "domain": 1, "level": 3, "question": "In a multi-cloud strategy, a key security challenge is:", "options": ["Inconsistent security controls and identity models across the different cloud providers", "The complete impossibility of encrypting data in more than one cloud provider at a time", "That all providers forcibly require customers to use one identical security tooling suite", "That adopting multi-cloud automatically removes every single point of failure by itself"], "correct": 0, "explanation": "Multi-cloud creates inconsistent controls and identity to reconcile; the distractors are false claims about cloud capabilities."},
  {"id": 70186, "domain": 1, "level": 2, "question": "A landing zone in cloud architecture provides:", "options": ["A physical staging area where servers are unboxed before installation into the racks", "A pre-configured, secure, and governed baseline environment for deploying new workloads", "An entirely unmanaged sandbox with no guardrails at all so teams can move very fast", "A backup vault that stores only the organization's oldest and least-accessed archives in this enterprise environment"], "correct": 1, "explanation": "A landing zone is a secure, governed baseline; the distractors describe physical staging, ungoverned sandboxes, or backups."},
  {"id": 70187, "domain": 1, "level": 3, "question": "Why are preventive guardrails such as service control policies preferred in cloud governance?", "options": ["They allow individual teams to freely bypass all of the organizational policies whenever in this enterprise environment", "They only ever work after an incident has already caused some measurable real damage", "They preventively enforce policy at scale without relying on slow human gatekeeping reviews", "They require every single change to be manually approved by one central review board"], "correct": 2, "explanation": "Guardrails enforce policy preventively at scale; the distractors describe bypasses, after-the-fact action, or manual bottlenecks."},
  {"id": 70188, "domain": 1, "level": 2, "question": "A web proxy with TLS inspection enables the organization to:", "options": ["Permanently decrypt and then store all of the user's online banking login credentials", "Eliminate entirely the need for any endpoint protection on the managed corporate devices", "Increase the encryption strength of every website that users visit fully automatically", "Inspect otherwise-encrypted web traffic for embedded threats and policy violations"], "correct": 3, "explanation": "TLS inspection lets a proxy examine encrypted traffic; it does not harvest credentials, replace endpoints, or strengthen sites."},
  {"id": 70189, "domain": 1, "level": 2, "question": "Network access control (NAC) enforces security by:", "options": ["Checking device posture and identity before granting any access to the internal network", "Encrypting all of the data that is stored on the connected client devices automatically", "Replacing the organization's existing firewalls with one single consolidated appliance", "Granting full unrestricted network access to literally any device that requests to join"], "correct": 0, "explanation": "NAC gates access based on posture and identity; it is not disk encryption, a firewall replacement, or open access."},
  {"id": 70190, "domain": 1, "level": 2, "question": "An air-gapped backup protects against ransomware because it:", "options": ["Is always kept connected to the live network in order to enable the fastest restores", "Is physically or logically isolated so that malware cannot reach and then encrypt it", "Relies solely on file permissions on the very same server as the production data set", "Is conveniently stored in the same location as the primary data for easy retrieval"], "correct": 1, "explanation": "Air-gapped backups are isolated from the network, resisting ransomware; the distractors describe connected, co-located copies."},
  {"id": 70191, "domain": 1, "level": 2, "question": "A content delivery network (CDN) can improve security posture by:", "options": ["Storing the single authoritative copy of the customer database at each separate edge node", "Replacing entirely the need for TLS by serving all of the content over plain HTTP instead", "Absorbing volumetric DDoS traffic and caching content closer to users at the edge", "Granting administrative access to the protected origin server for all of the edge users"], "correct": 2, "explanation": "A CDN absorbs DDoS and caches at the edge; it is not the database of record, a TLS replacement, or an admin gateway."},
  {"id": 70192, "domain": 1, "level": 2, "question": "In threat modeling, the STRIDE framework helps designers to:", "options": ["Encrypt all of the data flows automatically once the system design has been completed", "Replace penetration testing entirely with a single one-time documentation review exercise", "Guarantee that the resulting deployed system will end up having precisely zero vulnerabilities", "Systematically identify distinct categories of threats against a proposed system design"], "correct": 3, "explanation": "STRIDE enumerates threat categories during design; it does not encrypt, replace testing, or guarantee zero flaws."},
  {"id": 70193, "domain": 1, "level": 3, "question": "Why is establishing trust boundaries important in architecture design?", "options": ["They mark where data crosses between zones of differing trust and so require added controls", "They indicate clearly which servers can safely be left entirely unmonitored going forward", "They define the standardized physical color coding that is used in the datacenter cabling", "They remove the need for any authentication anywhere inside a defined trust boundary at all"], "correct": 0, "explanation": "Trust boundaries flag where controls are needed as data crosses zones; the distractors are irrelevant or insecure."},
  {"id": 70194, "domain": 1, "level": 1, "question": "A secure email gateway (SEG) primarily provides:", "options": ["Encryption of the organization's data while it is at rest on the corporate file servers", "Filtering of inbound phishing, malware, and spam messages before delivery to mailboxes", "Network segmentation between the operational technology and the corporate IT environments", "Automated provisioning of new user mailboxes and the assignment of software licenses"], "correct": 1, "explanation": "A SEG filters malicious inbound mail; encryption at rest, OT segmentation, and provisioning are different functions."},
  {"id": 70195, "domain": 1, "level": 3, "question": "Browser isolation improves web security architecture by:", "options": ["Permanently disabling the web browser entirely so that users cannot reach the internet", "Storing all of the user's browsing history unencrypted on one shared central server", "Executing untrusted web content within a remote sandbox kept away from the endpoint", "Replacing entirely the need for any DNS filtering or web proxy controls in the network"], "correct": 2, "explanation": "Browser isolation runs content remotely to protect endpoints; the distractors describe disabling, insecure storage, or removed controls."},
  {"id": 70196, "domain": 1, "level": 3, "question": "A key reason to deploy out-of-band management networks is to:", "options": ["Increase the total bandwidth that is available to the normal production user traffic", "Expose all of the device management interfaces directly to the open public internet", "Combine the management and the production traffic onto one single shared VLAN segment in this enterprise environment", "Administer devices over a separate path that survives a failure of the main data plane"], "correct": 3, "explanation": "OOB management uses a separate, resilient path; the distractors describe bandwidth, exposure, or insecure consolidation."},
  {"id": 70197, "domain": 1, "level": 3, "question": "Why is encrypting data in use, such as confidential computing, emerging as important?", "options": ["It protects data while it is being actively processed in memory, not only at rest or transit", "It eliminates entirely the need to ever encrypt any data at rest on the storage devices in this enterprise environment", "It only protects the data that has already been securely deleted from the live system", "It replaces all network encryption with one single in-memory protection control only"], "correct": 0, "explanation": "Confidential computing protects data during processing; the distractors misstate its scope versus rest and transit encryption."},
  {"id": 70198, "domain": 1, "level": 3, "question": "A blast radius reduction strategy in cloud accounts is to:", "options": ["Place every workload into one single shared account purely for centralized convenience", "Use separate accounts or subscriptions in order to contain the impact of a compromise", "Grant a single broad IAM role that has wide access across all of the environments at once", "Disable all logging entirely so that any incident leaves no trace at all to investigate"], "correct": 1, "explanation": "Account separation limits blast radius; single accounts, broad roles, and disabled logging enlarge or hide impact."},
  {"id": 70199, "domain": 1, "level": 2, "question": "A security benefit of well-designed API versioning is that it:", "options": ["Permanently locks the entire API so that no security fixes can ever be applied to it", "Eliminates entirely the need to authenticate any calls made to the newer API versions", "Allows deprecating insecure endpoints without immediately breaking all of the consumers", "Forces all of the clients to share a single static credential per each API version run in this enterprise environment"], "correct": 2, "explanation": "Versioning enables orderly deprecation of insecure endpoints; the distractors describe locking, removed auth, or shared creds."},
  {"id": 70200, "domain": 1, "level": 2, "question": "Rate limiting at the API layer primarily defends against:", "options": ["SQL injection that is embedded inside an otherwise well-formed valid request payload", "Physical theft of the actual servers that host the API within a secured datacenter rack", "Misconfigured IAM trust policies established between two separate cloud account tenants", "Abuse such as brute-force attempts, scraping, and certain denial-of-service patterns"], "correct": 3, "explanation": "Rate limiting curbs abuse and floods; SQLi needs input validation, and the other distractors are unrelated to throttling."},
  {"id": 70201, "domain": 1, "level": 3, "question": "Why should the management and data planes be separated in cloud network design?", "options": ["To prevent a compromise of workloads from directly exposing the administrative controls", "To ensure that all of the production traffic is routed through the central control plane", "To combine the credentials so that one key can manage both planes for added convenience", "To remove entirely the need for any authentication on the sensitive management plane"], "correct": 0, "explanation": "Plane separation keeps workload compromise from reaching admin controls; the distractors describe risky coupling or removed auth."},
  {"id": 70202, "domain": 1, "level": 2, "question": "A self-healing architecture improves resilience by:", "options": ["Requiring an on-call engineer to be paged for every single minor transient runtime error", "Automatically detecting failed components and replacing them without any manual action", "Ignoring all failures entirely so that the running system never has to react to an outage", "Shutting down the entire platform whenever any one individual node becomes unhealthy"], "correct": 1, "explanation": "Self-healing auto-replaces failed components; the distractors describe manual toil, ignored failures, or brittle shutdowns."},
  {"id": 70203, "domain": 1, "level": 2, "question": "Geographic redundancy across regions primarily protects against:", "options": ["Brute-force password guessing attacks aimed at a single individual user's account", "SQL injection flaws that happen to be present within the application's source code", "Region-wide outages such as natural disasters or a provider availability zone failure", "Excessive entitlements that were mistakenly granted to a single cloud service principal"], "correct": 2, "explanation": "Geo-redundancy survives region-level outages; password attacks, SQLi, and entitlements are unrelated to regional failover."},
  {"id": 70204, "domain": 1, "level": 3, "question": "A chaos engineering practice supports resilient architecture by:", "options": ["Removing all of the monitoring so that engineers are genuinely surprised by every outage", "Guaranteeing absolutely that no failure of any kind will ever occur in production again", "Replacing the backups entirely because the system is simply assumed to be unbreakable", "Deliberately injecting controlled failures to validate that systems recover as designed"], "correct": 3, "explanation": "Chaos engineering tests recovery via controlled failure injection; the distractors describe reduced visibility or false guarantees."},
  {"id": 70205, "domain": 1, "level": 3, "question": "In a layered email security architecture, DMARC reject enforcement causes:", "options": ["Unauthenticated messages spoofing the domain to be rejected by the receiving servers", "All inbound encrypted file attachments to be automatically quarantined upon arrival", "Internal mail to bypass all of the spam filtering entirely for the sake of faster delivery", "Outbound mail to be sent out without any signing or any sender alignment checks at all"], "correct": 0, "explanation": "A reject policy drops spoofed mail failing alignment; the distractors confuse DMARC with attachment, spam, or outbound handling."},
  {"id": 70206, "domain": 1, "level": 2, "question": "A security advantage of stateless application design is that it:", "options": ["Requires each request to carry along the user's plaintext account password every time", "Eases horizontal scaling and reduces the sensitive state stored on each individual node", "Forces all of the nodes to share one in-memory session that simply cannot ever be lost in this enterprise environment", "Permanently stores every single user session indefinitely on the local node disk drive"], "correct": 1, "explanation": "Stateless design scales easily and limits node-resident state; the distractors describe insecure or stateful anti-patterns."},
  {"id": 70207, "domain": 1, "level": 2, "question": "Why is certificate lifecycle management critical in PKI architecture?", "options": ["Certificates simply never expire, so any management effort can be safely ignored entirely", "Once issued, a certificate cannot ever be revoked again under any possible circumstances", "Expired or unrevoked certificates can cause outages or enable impersonation of services", "Lifecycle management only matters at all for self-signed certificates used in development"], "correct": 2, "explanation": "Lifecycle management prevents outages and impersonation from stale certs; the distractors deny expiry, revocation, or scope."},
  {"id": 70208, "domain": 1, "level": 3, "question": "OCSP stapling improves certificate validation by:", "options": ["Permanently caching certificates so that revocation never needs to be checked again", "Encrypting the certificate so that attackers are unable to read its embedded public key", "Replacing the certificate authority entirely with a peer-to-peer web of mutual trust", "Letting the server present a recent signed revocation status directly to its clients"], "correct": 3, "explanation": "OCSP stapling has the server provide fresh revocation status efficiently; the distractors misstate revocation and trust."},
  {"id": 70209, "domain": 1, "level": 1, "question": "A key principle of secure-by-design is that security should be:", "options": ["Built into the system from the very start rather than being bolted on afterward later", "Deferred until well after launch in order to avoid slowing the development team down", "Handled solely by a separate audit team only after the system has been deployed live", "Limited to documentation alone without ever affecting the actual system behavior at all"], "correct": 0, "explanation": "Secure-by-design integrates security from the start; the distractors describe bolt-on or after-the-fact approaches."},
  {"id": 70210, "domain": 1, "level": 1, "question": "Why are default-deny firewall rules considered a best practice?", "options": ["All traffic is allowed to pass freely unless an explicit block rule happens to exist for it", "Only explicitly permitted traffic is allowed to pass, which minimizes unintended exposure", "They remove the need to log or monitor any of the allowed connections going forward", "They automatically open up ports as the applications request them dynamically at runtime"], "correct": 1, "explanation": "Default-deny permits only allowed traffic; default-allow, removed logging, and auto-opening expand exposure."},
  {"id": 70211, "domain": 1, "level": 3, "question": "A security concern with serverless event-driven architectures is that:", "options": ["Functions run forever and thereby accumulate a very large persistent ongoing attack surface", "There is a single fixed public IP per function that attackers can freely scan and target", "Untrusted event sources can trigger functions with unexpected and possibly malicious input", "Functions simply cannot be granted any IAM permissions at all due to a design limitation"], "correct": 2, "explanation": "Event-driven functions must validate untrusted triggers and input; the distractors misstate serverless lifecycle and permissions."},
  {"id": 70212, "domain": 1, "level": 3, "question": "Sidecar proxies in a service mesh provide security by:", "options": ["Replacing the application code entirely with one single monolithic compiled binary file", "Storing all of the service credentials together in a shared world-readable plaintext file", "Disabling encryption between the services purely in order to improve the raw throughput", "Transparently adding mutual TLS, authorization, and telemetry to each individual service"], "correct": 3, "explanation": "Sidecars add mTLS, authz, and telemetry transparently; the distractors describe monolithic, insecure, or unencrypted designs."},
  {"id": 70213, "domain": 1, "level": 3, "question": "Why is image provenance important in container supply chain security?", "options": ["Verifying where an image came from helps prevent running tampered or malicious artifacts", "It guarantees that the image contains absolutely no software of any kind left to attack", "It allows skipping the vulnerability scanning of any base images deemed already trusted", "It makes the running container fully immune to all runtime exploitation attempts forever"], "correct": 0, "explanation": "Provenance verification blocks tampered images; the distractors overstate guarantees or wrongly skip scanning."},
  {"id": 70214, "domain": 1, "level": 2, "question": "A read-only root filesystem for containers improves security by:", "options": ["Allowing the container to freely modify any file on the underlying host that it chooses", "Preventing an attacker from writing malicious files into the running container filesystem", "Disabling all networking entirely so that the container can no longer communicate at all", "Permanently storing all of the application logs inside the original container image layers"], "correct": 1, "explanation": "A read-only root fs blocks malicious writes; the distractors describe host modification, broken networking, or log misplacement."},
  {"id": 70215, "domain": 1, "level": 2, "question": "Why might an organization use a forward proxy for outbound traffic?", "options": ["To serve as the single authoritative source of truth for all of the internal DNS zones", "To store the master encryption keys for every one of the corporate applications used", "To centrally enforce policy, inspect traffic, and log the users' outbound web activity", "To replace the need for installing endpoint antivirus on each managed workstation"], "correct": 2, "explanation": "A forward proxy enforces and logs outbound policy; it is not a DNS authority, key store, or antivirus replacement."},
  {"id": 70216, "domain": 1, "level": 2, "question": "The cattle-not-pets approach to servers supports security by:", "options": ["Manually nursing each unique server through many years of careful in-place changes", "Naming each individual server so that the administrators grow attached to each one", "Avoiding automation so that every change is always performed by hand very carefully in this enterprise environment", "Treating servers as disposable and easily replaceable, which reduces long-lived risk"], "correct": 3, "explanation": "Disposable servers reduce drift and long-lived compromise; the distractors describe pet-style, drift-prone management."},
  {"id": 70217, "domain": 1, "level": 3, "question": "A security benefit of using managed identities in cloud is that they:", "options": ["Eliminate hardcoded credentials by letting the platform issue and rotate access tokens", "Require developers to embed long-lived static secrets directly into the application source", "Share one common identity across every workload purely for simpler central management", "Disable all authentication between the cloud services in order to reduce request latency"], "correct": 0, "explanation": "Managed identities remove hardcoded creds via platform-issued tokens; the distractors describe insecure credential practices."},
  {"id": 70218, "domain": 1, "level": 2, "question": "Why is logging and telemetry considered an architectural concern rather than an afterthought?", "options": ["Logs are only ever useful for billing reconciliation and carry no real security relevance in this enterprise environment", "Detection and response depend on designing observability into the systems right from the start", "Telemetry should be disabled in production purely in order to maximize raw performance", "Observability can always be fully retrofitted with no difficulty after a breach occurs"], "correct": 1, "explanation": "Observability must be designed in to enable detection and response; the distractors dismiss or defer its security value."},
  {"id": 70219, "domain": 1, "level": 2, "question": "A trusted platform module (TPM) supports endpoint architecture by:", "options": ["Serving as the primary network firewall for the entire subnet that the host belongs to in this enterprise environment", "Storing the user's documents within an encrypted cloud synchronization folder for them", "Providing hardware-based key storage along with measured and verified secure boot integrity", "Acting as a software antivirus engine that scans files on demand whenever requested"], "correct": 2, "explanation": "A TPM provides hardware key storage and boot integrity; it is not a firewall, cloud sync, or antivirus engine."},
  {"id": 70220, "domain": 1, "level": 2, "question": "Why is segmenting the management VLAN from the user VLANs recommended?", "options": ["It allows users to administer the network devices themselves for faster troubleshooting", "It combines all of the traffic so that a single ACL can govern everything at once neatly", "It removes the need to authenticate at all to any of the network device interfaces", "It prevents ordinary users from reaching the sensitive device management interfaces"], "correct": 3, "explanation": "Separating the management VLAN shields admin interfaces; the distractors describe exposure, consolidation, or removed auth."},
  {"id": 70221, "domain": 1, "level": 2, "question": "A key design consideration for hybrid cloud connectivity is:", "options": ["Securing and encrypting the network link between the on-premises and cloud environments", "Exposing the on-premises Active Directory service directly to the open public internet", "Disabling identity federation entirely so that each environment remains fully separate", "Routing all of the cloud-bound traffic through a single unencrypted public network path"], "correct": 0, "explanation": "Hybrid links must be secured and encrypted; exposing AD, disabling federation, and unencrypted paths are insecure."},
  {"id": 70222, "domain": 1, "level": 3, "question": "Why is attribute-based access control (ABAC) useful in dynamic environments?", "options": ["It assigns one single fixed role to every user that can then never be changed afterward", "It makes access decisions from attributes and context rather than from static roles alone", "It deliberately ignores all environmental context when it authorizes any incoming request", "It requires explicit manual approval for each and every individual access request made"], "correct": 1, "explanation": "ABAC uses attributes and context for flexible decisions; the distractors describe rigid, context-blind, or manual approaches."},
  {"id": 70223, "domain": 1, "level": 2, "question": "A primary reason to centralize logging in a SIEM is to:", "options": ["Reduce total storage usage by discarding the logs as soon as they happen to arrive in", "Prevent any of the analysts from ever being able to query the historical event data", "Correlate events across many systems in order to detect multi-stage coordinated attacks", "Ensure that each system only ever analyzes its own logs in complete isolation from others"], "correct": 2, "explanation": "A SIEM correlates cross-system events for detection; the distractors discard data, block queries, or silo analysis."},
  {"id": 70224, "domain": 1, "level": 3, "question": "Why is a phased microsegmentation rollout typically recommended?", "options": ["Applying a deny-all policy everywhere immediately is completely risk-free and instant", "Segmentation requires no understanding at all of the existing application traffic flows", "All applications behave identically, so one single policy will fit every workload neatly", "Mapping the existing flows first avoids breaking legitimate traffic when policy tightens"], "correct": 3, "explanation": "Phased rollout maps flows to avoid outages; the distractors ignore application behavior and overstate simplicity."},
  {"id": 70225, "domain": 1, "level": 3, "question": "A deception technology platform extends honeypots by:", "options": ["Distributing decoy assets and breadcrumbs broadly in order to detect intruders early", "Serving as the primary production identity provider for all of the organization's employees", "Encrypting all of the backups before they are written out to the offsite cold storage", "Replacing the organization's entire firewall and intrusion prevention stack by itself"], "correct": 0, "explanation": "Deception platforms scatter decoys and breadcrumbs for early detection; the distractors describe IdP, backup, and firewall roles."},
  {"id": 70226, "domain": 1, "level": 2, "question": "Why is reducing implicit trust between internal services important?", "options": ["Internal services are inherently safe by nature and so never require any authentication", "A single compromised internal service should not automatically be able to reach all others", "Mutual authentication between the services adds no measurable security value whatsoever", "Once any traffic is inside the perimeter it can simply be fully trusted by default always in this enterprise environment"], "correct": 1, "explanation": "Limiting internal implicit trust contains compromise; the distractors reflect the discredited trusted-internal-network model."},
  {"id": 70227, "domain": 1, "level": 3, "question": "A web application architecture using same-site cookies helps mitigate:", "options": ["SQL injection occurring within the application's own backend relational database queries", "Physical tampering with the web server hardware while it sits in the datacenter rack", "Cross-site request forgery by restricting when cookies are sent on cross-origin requests", "Excessive IAM permissions that were mistakenly assigned to a cloud service account"], "correct": 2, "explanation": "SameSite cookies reduce CSRF exposure; SQLi, physical tampering, and IAM are unrelated to cookie scoping."},
  {"id": 70228, "domain": 1, "level": 2, "question": "Why is input validation considered an architectural control rather than just coding hygiene?", "options": ["Input validation only matters at the user interface and is never needed at the backend", "Each developer should invent a unique ad hoc validation routine for every endpoint built", "Validation can be skipped entirely as long as the underlying database is encrypted at rest", "Consistent validation boundaries across the services prevent injection attacks at scale"], "correct": 3, "explanation": "Architectural validation boundaries stop injection consistently; the distractors trivialize or scatter the control."},
  {"id": 70229, "domain": 1, "level": 2, "question": "A key purpose of a configuration management database (CMDB) in security is to:", "options": ["Provide an authoritative asset inventory that enables accurate risk and patch decisions", "Serve as the primary network firewall that enforces all of the access rules for traffic", "Encrypt every single asset's stored data at rest using a single centralized key store", "Replace the need for any vulnerability scanning across the whole organizational estate"], "correct": 0, "explanation": "A CMDB inventories assets to inform risk and patching; it is not a firewall, key store, or scanner replacement."},
  {"id": 70230, "domain": 1, "level": 2, "question": "Why is east-west traffic visibility often a gap in traditional architectures?", "options": ["Internal traffic is always fully encrypted and therefore never needs any inspection at all", "Perimeter-focused designs inspect north-south traffic but largely miss internal flows", "East-west traffic never carries any data that would ever be worth monitoring closely", "Network switches automatically block all lateral movement between hosts by default"], "correct": 1, "explanation": "Perimeter designs miss internal east-west flows; the distractors falsely assume internal traffic is safe or auto-blocked."},
  {"id": 70231, "domain": 1, "level": 3, "question": "A primary advantage of policy-as-code in security architecture is:", "options": ["Policies that exist only as unenforced PDF documents left on a shared network drive", "Manual interpretation of the policy by each separate team in its own differing way", "Versioned, testable, and automatically enforced policies applied across all environments", "Policies that simply cannot be reviewed, tested, or changed once they are first written in this enterprise environment"], "correct": 2, "explanation": "Policy-as-code is versioned, testable, and auto-enforced; the distractors describe unenforced or unmanageable policy."},
  {"id": 70232, "domain": 1, "level": 1, "question": "Why is a single flat network considered a security anti-pattern?", "options": ["Flat networks automatically encrypt all of the traffic between every connected host pair", "Flat networks make it entirely impossible for any device to communicate with any other", "Flat networks inherently enforce strict least privilege between all of the connected hosts", "A breach anywhere can move laterally to reach every system without any internal barriers"], "correct": 3, "explanation": "Flat networks allow unrestricted lateral movement; the distractors falsely credit them with encryption or segmentation."},
  {"id": 70233, "domain": 1, "level": 3, "question": "A benefit of using short-lived certificates over long-lived ones is:", "options": ["A reduced impact window if a key is compromised, since the certificate expires very soon", "Eliminating entirely the need to ever rotate or manage any of the certificates again", "Permanently trusting a key so that revocation infrastructure becomes wholly unnecessary in this enterprise environment", "Allowing the very same certificate to be reused across many unrelated separate systems"], "correct": 0, "explanation": "Short-lived certs shrink the compromise window; the distractors deny rotation, revocation, or proper scoping."},
  {"id": 70234, "domain": 1, "level": 2, "question": "Why is a defense-in-depth approach applied to cloud storage buckets?", "options": ["A single public-read setting is entirely sufficient protection for highly sensitive data", "Combining IAM, bucket policy, encryption, and logging guards against any single failure", "Encryption alone removes the need for any access control whatsoever on the storage bucket", "Enabling logging makes all of the other storage controls completely unnecessary at once"], "correct": 1, "explanation": "Layered bucket controls guard against any single misconfiguration; the distractors rely on one inadequate control."},
  {"id": 70235, "domain": 1, "level": 2, "question": "A purpose of a security reference architecture is to:", "options": ["Document one single unique design that can then never be reused anywhere else again in this enterprise environment", "Replace entirely the need for performing any threat modeling on brand-new projects", "Provide reusable, vetted design patterns that teams can adopt consistently across projects", "Mandate that every separate team must invent all of its own controls from scratch"], "correct": 2, "explanation": "Reference architectures supply reusable vetted patterns; the distractors describe one-offs, skipped modeling, or duplicated effort."},
  {"id": 70236, "domain": 1, "level": 2, "question": "Why should secrets never be baked into container images?", "options": ["Container images are encrypted by default so any embedded secrets are always kept safe", "Container images simply cannot store text, so embedded secrets would be lost anyway", "Embedded secrets automatically rotate themselves every time the container is run again", "Anyone who pulls the image can extract the embedded secrets directly from its layers"], "correct": 3, "explanation": "Image layers expose embedded secrets to anyone with the image; the distractors falsely claim safety or rotation."},
  {"id": 70237, "domain": 1, "level": 1, "question": "A primary security goal of network traffic encryption such as IPsec is to:", "options": ["Protect the confidentiality and integrity of data as it crosses untrusted networks", "Increase the raw throughput that is available on the underlying physical network links", "Eliminate entirely the need for authentication of the two communicating endpoints", "Guarantee that the network will simply never experience any packet loss at all again"], "correct": 0, "explanation": "Traffic encryption protects confidentiality and integrity in transit; it does not boost throughput, remove auth, or prevent loss."},
  {"id": 70238, "domain": 1, "level": 3, "question": "Why is centralized identity governance valuable across many SaaS applications?", "options": ["It lets each SaaS application manage its own disconnected identities indefinitely forever", "It provides consistent provisioning, regular access reviews, and timely deprovisioning", "It removes entirely the need to ever review or revoke any user's access going forward", "It guarantees that no user will ever be over-provisioned within any system at all ever"], "correct": 1, "explanation": "Central governance standardizes lifecycle and reviews; the distractors describe silos, skipped reviews, or false guarantees."},
  {"id": 70239, "domain": 1, "level": 3, "question": "A reason to deploy decoy credentials, or honey accounts, in Active Directory is to:", "options": ["Provide legitimate administrators with an easy shared backup login for emergencies only", "Replace entirely the need for monitoring the activity of the real privileged accounts", "Generate high-fidelity alerts whenever an attacker attempts to use one of the accounts", "Grant emergency access to any user who happens to discover the hidden account exists"], "correct": 2, "explanation": "Honey accounts alert on attacker use; they are not legitimate logins, monitoring replacements, or emergency access."},
  {"id": 70240, "domain": 1, "level": 2, "question": "Why is a well-defined data retention and disposal architecture important?", "options": ["Keeping absolutely all data forever will always minimize the organization's total risk", "Secure disposal is entirely unnecessary because any deleted data is already unrecoverable", "Retention policies have no effect at all on the organization's overall attack surface", "Limiting the amount of data retained reduces exposure and breach impact over the long run"], "correct": 3, "explanation": "Minimizing retained data reduces exposure; the distractors wrongly favor indefinite retention or dismiss disposal."},
  {"id": 70241, "domain": 1, "level": 2, "question": "A security advantage of using infrastructure templates such as golden images is:", "options": ["Consistent, hardened baselines that are deployed repeatably across the entire server fleet", "Each instance is hand-configured uniquely, which then ensures the maximum possible variation", "Hardening is skipped completely because the templates are inherently fully trustworthy", "The templates actively prevent any future patching of the instances that were deployed"], "correct": 0, "explanation": "Golden images give consistent hardened baselines; the distractors describe drift, skipped hardening, or blocked patching."},
  {"id": 70242, "domain": 1, "level": 3, "question": "Why is the control plane of a Kubernetes cluster a high-value target?", "options": ["The control plane only ever stores logs and holds no operational authority of any kind", "Compromising the API server can grant attacker control over all workloads and secrets", "It is fully isolated from the workloads and so cannot affect any of them in any way", "It holds no credentials at all, so compromising it yields no advantage to an attacker"], "correct": 1, "explanation": "The API server controls workloads and secrets; the distractors understate the control plane's authority and value."},
  {"id": 70243, "domain": 1, "level": 3, "question": "A purpose of mutual authentication in IoT architecture is to:", "options": ["Let any device join the platform without ever presenting any credentials whatsoever", "Authenticate only the platform itself while implicitly trusting every connecting device", "Ensure that both the device and the platform verify each other before communicating", "Replace device firmware signing entirely with one single shared network access password"], "correct": 2, "explanation": "Mutual auth verifies both device and platform; the distractors describe open joining, one-sided trust, or weak shared secrets."},
  {"id": 70244, "domain": 1, "level": 3, "question": "Why is rate limiting alone insufficient against application-layer DDoS?", "options": ["Rate limiting on its own fully blocks every possible denial-of-service technique that exists", "Application-layer DDoS does not actually exist, so no defense against it is ever needed", "Rate limiting also encrypts the traffic, which makes any further controls fully redundant", "Sophisticated attacks closely mimic legitimate users and require deeper behavioral analysis"], "correct": 3, "explanation": "Layer-7 DDoS mimics real users, needing behavioral defenses; the distractors overstate or deny the threat."},
  {"id": 70245, "domain": 1, "level": 3, "question": "A benefit of designing idempotent APIs from a resilience standpoint is:", "options": ["Safe retries during transient failures without ever causing duplicate side effects", "Each retry intentionally creates a brand-new duplicate transaction record every time", "Clients are completely prevented from ever retrying a failed request a second time", "The API stores plaintext credentials specifically to speed up repeated identical calls"], "correct": 0, "explanation": "Idempotency makes retries safe without duplicates; the distractors describe duplication, blocked retries, or insecure storage."},
  {"id": 70246, "domain": 1, "level": 2, "question": "Why is least privilege applied to service accounts as well as to human users?", "options": ["Service accounts are inherently safe by design and so need no permission limits at all in this enterprise environment", "Over-privileged service accounts are prime targets for lateral movement and broad abuse", "Service accounts simply cannot be compromised, so their granted scope is irrelevant", "Granting service accounts full admin rights actually simplifies troubleshooting safely"], "correct": 1, "explanation": "Over-privileged service accounts enable abuse and lateral movement; the distractors wrongly assume they are safe."},
  {"id": 70247, "domain": 1, "level": 2, "question": "A reason to deploy a WAF in front of APIs as well as web apps is that:", "options": ["APIs are inherently immune to all application-layer attacks simply by their own nature", "A WAF placed on the APIs removes the need for any authentication on the incoming calls", "APIs face injection, abuse, and schema attacks that benefit from layer-7 traffic filtering", "APIs cannot be protected by any control other than a basic network firewall at the edge in this enterprise environment"], "correct": 2, "explanation": "APIs need layer-7 protection too; the distractors deny API threats, conflate WAF with auth, or limit options falsely."},
  {"id": 70248, "domain": 1, "level": 2, "question": "Why is a clear separation between production and non-production environments important?", "options": ["It allows developers to use the live customer data freely within their testing environments in this enterprise environment", "It combines all of the environments together to simplify a single shared security policy", "It removes entirely the need to apply any security to the non-production environments", "It prevents test activity and weaker controls from accidentally exposing real production data"], "correct": 3, "explanation": "Environment separation protects production data from weaker test controls; the distractors describe risky commingling."},
  {"id": 70249, "domain": 1, "level": 2, "question": "A primary benefit of using a dedicated identity provider over per-application accounts is:", "options": ["Centralized control of authentication policy, MFA enforcement, and account lifecycle", "Each application independently storing and managing its own separate password database", "Eliminating the ability to enforce MFA consistently across the whole organization at all", "Requiring every user to remember a separate distinct credential for each different service"], "correct": 0, "explanation": "A central IdP unifies auth policy and lifecycle; the distractors describe fragmented, weaker identity management."},
  {"id": 70250, "domain": 1, "level": 1, "question": "Why is encrypting backups as important as encrypting the production data itself?", "options": ["Backups contain only meaningless throwaway data that needs no real protection at all", "Backups contain the very same sensitive data and so are attractive theft targets too", "Encrypting the backups actually prevents them from ever being restored again later on", "Backup encryption is unnecessary purely because backups are assumed to be always offline"], "correct": 1, "explanation": "Backups hold the same sensitive data and must be encrypted; the distractors dismiss their sensitivity or restorability."},
  {"id": 70251, "domain": 1, "level": 2, "question": "A purpose of network tap or SPAN ports in security architecture is to:", "options": ["Increase the encryption strength of all of the mirrored network traffic automatically", "Block malicious traffic inline before it is ever able to reach its intended destination", "Provide visibility by mirroring traffic to monitoring and threat detection tools", "Serve as the primary routing path that carries all of the production data flows along"], "correct": 2, "explanation": "Taps and SPAN ports mirror traffic for monitoring; they do not encrypt, block inline, or carry primary routing."},
  {"id": 70252, "domain": 1, "level": 3, "question": "Why is designing for token revocation important in OAuth and OIDC architectures?", "options": ["Tokens are inherently safe by design and so never need to be revoked at any point", "Revocation makes it permanently impossible for any user to ever authenticate again", "Once issued, a token should remain valid forever purely for ongoing user convenience", "Compromised or stale tokens must be invalidated before they naturally reach expiry"], "correct": 3, "explanation": "Revocation contains compromised tokens before natural expiry; the distractors deny the need or break authentication."},
  {"id": 70253, "domain": 1, "level": 3, "question": "A security reason to isolate CI/CD pipeline runners is that:", "options": ["A compromised pipeline could otherwise reach production systems and secrets directly", "Build runners legitimately need full administrative access to every production host", "Isolating the runners would prevent any code from ever being built or shipped at all", "Pipelines never handle any secrets, so isolating the runners provides no benefit at all"], "correct": 0, "explanation": "Isolating runners limits pipeline-to-production blast radius; the distractors overstate access or deny pipeline risk."},
  {"id": 70254, "domain": 1, "level": 2, "question": "Why is monitoring DNS queries valuable within a security architecture?", "options": ["DNS traffic never carries any indicators of malicious activity that are worth examining", "Many malware and exfiltration techniques rely on DNS that monitoring can readily reveal", "Monitoring DNS encrypts all of the queries and removes the need for any DNS filtering", "DNS is only ever used for performance tuning and provides no useful security insight"], "correct": 1, "explanation": "DNS monitoring exposes C2 and exfiltration patterns; the distractors deny DNS's security relevance."},
  {"id": 70255, "domain": 1, "level": 3, "question": "A reason to architect defenses against SSRF in cloud-hosted applications is that:", "options": ["SSRF only ever affects on-premises systems and never touches any cloud workloads", "Cloud platforms automatically block every single SSRF attempt that occurs by default", "SSRF can reach internal metadata endpoints and then harvest live cloud credentials", "SSRF can only read public web pages and is unable to reach any internal resources"], "correct": 2, "explanation": "SSRF can hit cloud metadata services to steal credentials; the distractors understate or deny the cloud risk."},
  {"id": 70256, "domain": 1, "level": 2, "question": "Why is a tiered storage architecture relevant to data security?", "options": ["All data must be stored in exactly the same way regardless of its actual sensitivity in this enterprise environment", "Tiering completely removes the need to encrypt any of the data that is being stored", "Storage tiers only ever affect cost and carry no security implications of any kind", "Sensitivity-based tiers let the applied controls and encryption match the data's value"], "correct": 3, "explanation": "Tiering aligns controls with data sensitivity; the distractors flatten data handling or dismiss security relevance."},
  {"id": 70257, "domain": 1, "level": 2, "question": "A benefit of using a dedicated bastion subnet with strict ingress is:", "options": ["Administrative access is funneled through one small, heavily monitored entry pathway", "Every internal host becomes directly reachable from the open public internet always", "Administrators no longer need to authenticate at all to reach the internal systems", "All of the production traffic is forced to traverse the bastion for its normal routing"], "correct": 0, "explanation": "A bastion subnet narrows and monitors admin ingress; the distractors describe exposure, removed auth, or misrouting."},
  {"id": 70258, "domain": 1, "level": 3, "question": "Why is it important to validate webhooks received from third parties?", "options": ["Webhooks are inherently trusted purely because they arrive over the public internet", "Unverified webhooks can be forged by attackers to trigger unauthorized backend actions", "Validating webhooks makes the receiving endpoint permanently impossible to ever reach", "Webhooks never carry any data that could meaningfully affect application behavior at all"], "correct": 1, "explanation": "Webhook signatures prevent forged triggers; the distractors assume trust, break the endpoint, or deny impact."},
  {"id": 70259, "domain": 1, "level": 3, "question": "A reason to architect for token binding or proof-of-possession is to:", "options": ["Allow any party that merely holds a token to use it freely without any restriction at all", "Eliminate entirely the need to ever encrypt the tokens while they are in transit", "Prevent stolen bearer tokens from being successfully replayed by an attacker elsewhere", "Permanently extend the token lifetimes purely for the sake of end-user convenience"], "correct": 2, "explanation": "Proof-of-possession and token binding stop token replay; the distractors describe unrestricted bearer use or weakened controls."},
  {"id": 70260, "domain": 1, "level": 1, "question": "Why is segmenting guest Wi-Fi from the corporate network a standard practice?", "options": ["Guest and corporate traffic should simply share one common VLAN for added simplicity", "Guest network clients should be given full access to all of the internal file shares", "Segmenting the guest Wi-Fi actually provides no measurable security benefit at all", "Untrusted guest devices should not be able to reach the internal corporate resources"], "correct": 3, "explanation": "Guest segmentation keeps untrusted devices off corporate resources; the distractors describe insecure commingling."},
  {"id": 70261, "domain": 1, "level": 2, "question": "A purpose of designing clear API authentication and authorization layers is to:", "options": ["Ensure every request proves its identity and is checked against the granted permissions", "Allow anonymous unauthenticated callers to perform privileged operations entirely freely", "Trust the connecting client to enforce all of the access decisions entirely on its own", "Authenticate the user once and then skip all authorization checks on every later call"], "correct": 0, "explanation": "APIs must authenticate and authorize each request; the distractors permit anonymous, client-side, or skipped checks."},
  {"id": 70262, "domain": 1, "level": 2, "question": "Why is a runbook-driven, automated recovery process valuable for resilience?", "options": ["It guarantees absolutely that incidents will simply never occur in the environment again", "It reduces human error and shortens recovery time during high-pressure live incidents", "It removes entirely the need to back up data because the recovery is now fully automated", "It ensures that recovery will always require extensive on-the-spot manual improvisation"], "correct": 1, "explanation": "Automated runbooks cut error and recovery time; the distractors overpromise prevention or contradict automation."},
  {"id": 70263, "domain": 1, "level": 3, "question": "A reason to use envelope encryption for data at rest is that it:", "options": ["Stores the actual encryption key in plaintext right alongside the encrypted data records", "Uses a single static key for all of the data so that key rotation is never needed at all", "Encrypts the data with a data key that is itself then protected by a separate master key", "Removes the need to control access to the underlying key management service in any way"], "correct": 2, "explanation": "Envelope encryption wraps data keys under a master key for manageable rotation; the distractors describe insecure key handling."},
  {"id": 70264, "domain": 1, "level": 2, "question": "Why is mapping third-party and SaaS data flows part of security architecture?", "options": ["Data sent off to any third parties is automatically secured by that vendor entirely alone", "External data flows have no bearing whatsoever on the organization's overall risk posture", "Once data leaves the perimeter it is simply no longer the organization's concern at all", "Sensitive data leaving to external services needs proportionate controls and oversight"], "correct": 3, "explanation": "External data flows require oversight and controls; the distractors offload or dismiss third-party data risk."},
  {"id": 70265, "domain": 1, "level": 3, "question": "A security benefit of using ephemeral build environments is that they:", "options": ["Reduce the persistent attack surface by being fully destroyed after each individual build", "Persist indefinitely so that attackers can keep a stable long-term foothold within them in this enterprise environment", "Share one single long-lived environment across all of the teams and all of the projects", "Accumulate state and secrets over time specifically in order to speed up future builds"], "correct": 0, "explanation": "Ephemeral builds shrink the persistent attack surface; the distractors describe long-lived, state-accumulating environments."},
  {"id": 70266, "domain": 1, "level": 1, "question": "Why is it risky to expose a database directly to the internet?", "options": ["Databases are inherently fully immune to any attack whenever they are made internet-facing", "It removes the protective network layers of defense and invites direct attack on the data", "Direct internet exposure conveniently encrypts all of the stored records automatically", "Internet-facing databases simply cannot be scanned or discovered by any external attacker"], "correct": 1, "explanation": "Direct database exposure strips defensive layers; the distractors falsely claim immunity, encryption, or invisibility."},
  {"id": 70267, "domain": 1, "level": 2, "question": "A reason to implement HSTS within a web architecture is to:", "options": ["Allow browsers to silently fall back to plain HTTP whenever doing so is more convenient", "Encrypt the web server's locally stored files while they are at rest on the disk drive", "Force browsers to use HTTPS and thereby resist any protocol downgrade attacks attempted", "Replace entirely the need for a valid TLS certificate to be installed on the website"], "correct": 2, "explanation": "HSTS enforces HTTPS and blocks downgrades; the distractors describe HTTP fallback, at-rest encryption, or removed certs."},
  {"id": 70268, "domain": 1, "level": 2, "question": "Why is identity considered the new perimeter in modern security architecture?", "options": ["Network firewalls alone now fully define and completely enforce all of the trust decisions", "The user's physical location remains the only meaningful security boundary that matters", "Identity becomes entirely irrelevant once a device is connected to the corporate network", "With network boundaries dissolving, identity now governs access to the actual resources"], "correct": 3, "explanation": "Identity governs access as network boundaries dissolve; the distractors cling to perimeter or location-based trust."},
  {"id": 70269, "domain": 1, "level": 3, "question": "A purpose of designing for blast-radius containment in microservices is to:", "options": ["Ensure that a single compromised service cannot cascade across the whole wider system", "Allow one failing service to deliberately bring down every other service all at once in this enterprise environment", "Share a single common database and one credential set across all of the services run", "Remove all of the boundaries so that services can call each other without any limits"], "correct": 0, "explanation": "Containment stops cascading compromise; the distractors describe coupling that enlarges blast radius."},
  {"id": 70270, "domain": 1, "level": 3, "question": "Why is continuous compliance monitoring via CSPM preferred over point-in-time audits?", "options": ["Cloud configurations simply never change at all once they have been initially deployed in this enterprise environment", "Cloud changes constantly, so drift must be detected continuously rather than once a year", "A single annual audit fully captures all of the ongoing cloud risk for the whole year", "Continuous monitoring conveniently removes the need to ever remediate any findings"], "correct": 1, "explanation": "Continuous monitoring catches constant cloud drift; the distractors assume static configs or dismiss remediation."},
  {"id": 70271, "domain": 1, "level": 3, "question": "A reason to architect mutual distrust between tiers such as web and database is:", "options": ["The web tier should simply share the full database admin credentials for added speed", "Tiers inside the same datacenter never need to authenticate to one another at any point", "A compromised web tier should not then have unrestricted access into the database tier", "All of the tiers should trust each other implicitly purely to reduce request latency"], "correct": 2, "explanation": "Tier distrust limits compromise spread; the distractors describe shared creds and implicit inter-tier trust."},
  {"id": 70272, "domain": 1, "level": 1, "question": "Why is a documented secure baseline configuration important for new systems?", "options": ["It allows each administrator to configure the systems however he or she happens to prefer", "Baselines guarantee that the systems will never need any patching at all after deployment", "A baseline removes the need to ever monitor the systems for any configuration drift later", "It ensures every system starts from a known, hardened, and fully repeatable secure state"], "correct": 3, "explanation": "Baselines give hardened, repeatable starting points; the distractors describe ad hoc configs or skipped maintenance."},
  {"id": 70273, "domain": 1, "level": 2, "question": "A reason to use private endpoints for cloud services is to:", "options": ["Keep the traffic on the provider's private network and entirely off the public internet", "Expose every single managed service directly to the open public internet by default", "Disable all authentication entirely just because the service endpoint is now private", "Route the service traffic through the slowest available public path on purpose always in this enterprise environment"], "correct": 0, "explanation": "Private endpoints keep traffic off the public internet; the distractors describe exposure, removed auth, or misrouting."},
  {"id": 70274, "domain": 1, "level": 3, "question": "Why is designing for secure secrets injection at runtime preferred?", "options": ["Secrets are hardcoded directly into the application binary purely for the fastest access", "Secrets are delivered to the workload without ever being stored within code or images", "Secrets are printed out to standard output so that they are very easy to audit later", "Secrets are shared identically across every single environment for the sake of consistency"], "correct": 1, "explanation": "Runtime injection avoids embedding secrets in code or images; the distractors describe hardcoding, leakage, or reuse."},
  {"id": 70275, "domain": 1, "level": 3, "question": "A purpose of network behavior analytics in security architecture is to:", "options": ["Replace all of the encryption entirely with statistical traffic analysis techniques instead", "Guarantee the detection of every single possible attack with exactly zero false positives", "Detect anomalies that signature-based tools may miss within the internal traffic flows", "Eliminate the need to log or retain any of the network traffic data going forward at all"], "correct": 2, "explanation": "Behavior analytics finds anomalies beyond signatures; the distractors overstate guarantees or remove logging."},
  {"id": 70276, "domain": 1, "level": 3, "question": "Why is least-privilege network design with default-deny east-west increasingly adopted?", "options": ["It assumes that the internal network is always fully trustworthy under all circumstances", "It allows every single workload to freely reach every other workload without any limits", "It removes the need to authenticate any of the internal service-to-service calls at all", "It assumes a breach has occurred and limits how far an intruder can then move internally"], "correct": 3, "explanation": "Default-deny east-west assumes breach and limits movement; the distractors reflect the old trusted-internal model."},
  {"id": 70277, "domain": 1, "level": 3, "question": "A reason to architect for certificate transparency monitoring is to:", "options": ["Detect any unauthorized certificates that were issued for the organization's own domains", "Encrypt the organization's certificates so that no attacker is ever able to read them", "Automatically renew every single one of the certificates well before it can ever expire in this enterprise environment", "Replace the certificate authority entirely with a public distributed ledger of secrets"], "correct": 0, "explanation": "CT monitoring spots rogue certs for your domains; the distractors confuse it with encryption, renewal, or CA replacement."},
  {"id": 70278, "domain": 1, "level": 2, "question": "Why is segregating duties between developers and production access important?", "options": ["It lets the developers freely deploy any change at all directly into production systems", "It prevents a single person from both introducing and deploying malicious code unchecked", "It removes the need for any code review since the access has already been split apart", "It combines the build and the deploy authority into one single role purely for efficiency"], "correct": 1, "explanation": "Segregating dev and prod access prevents unchecked malicious deploys; the distractors recombine duties or skip review."},
  {"id": 70279, "domain": 1, "level": 2, "question": "A purpose of designing explicit data residency controls is to:", "options": ["Allow data to be freely replicated into any region at all without any restriction at all", "Guarantee that the data simply can never be accessed again once it has been stored away", "Ensure that regulated data stays within the approved geographic or legal jurisdictions", "Remove the need to encrypt any data as long as it always stays within one single country"], "correct": 2, "explanation": "Residency controls keep regulated data in approved jurisdictions; the distractors ignore residency or conflate it with other controls."},
  {"id": 70280, "domain": 1, "level": 2, "question": "Why is a layered approach to email security across gateway, authentication, and training recommended?", "options": ["A single spam filter on its own is fully sufficient to stop every phishing attempt made", "User training all by itself eliminates the need for any technical email controls at all", "Email authentication alone makes both the gateways and the training entirely redundant", "No single control stops all phishing, so overlapping defenses meaningfully reduce risk"], "correct": 3, "explanation": "Layered email defenses cover each other's gaps; the distractors rely on one inadequate control."},
  {"id": 70281, "domain": 1, "level": 3, "question": "A reason to architect for graceful certificate rotation is to:", "options": ["Replace expiring certificates without any service downtime or resulting gaps in trust", "Allow the certificates to expire abruptly and thereby cause unplanned service outages", "Use the very same certificate forever so that rotation never disrupts the service at all", "Remove entirely the requirement to validate any certificates after a rotation has occurred"], "correct": 0, "explanation": "Graceful rotation avoids downtime and trust gaps; the distractors describe abrupt expiry or never rotating."},
  {"id": 70282, "domain": 1, "level": 2, "question": "Why is it important to design APIs with explicit schema validation?", "options": ["Accepting any input shape at all makes the API more secure by being maximally flexible in this enterprise environment", "Rejecting malformed or unexpected input reduces the injection and the abuse risk overall", "Schema validation always prevents the API from ever returning any response to a caller", "Validation is only ever needed on responses and is never required on incoming requests"], "correct": 1, "explanation": "Schema validation rejects malicious or unexpected input; the distractors invite abuse or misplace validation."},
  {"id": 70283, "domain": 1, "level": 3, "question": "A reason to use a dedicated security account for logging in multi-account cloud is:", "options": ["Storing the logs inside each workload account where any attacker can simply delete them", "Keeping the logs only on the compromised host itself for the fastest possible local access in this enterprise environment", "Centralized, tamper-resistant log storage that is fully isolated from the workload accounts", "Disabling all cross-account logging purely in order to simplify the account structure"], "correct": 2, "explanation": "A separate logging account protects log integrity from workload compromise; the distractors leave logs deletable or unaggregated."},
  {"id": 70284, "domain": 1, "level": 3, "question": "Why is designing for the principle of complete mediation important?", "options": ["Only the initial access ever needs checking; all of the later requests can be trusted", "Access decisions can be cached forever once the user has authenticated successfully once in this enterprise environment", "Complete mediation only ever applies to network traffic and never to application objects", "Every access to a resource must be checked, not merely the very first request that arrives"], "correct": 3, "explanation": "Complete mediation checks every access; the distractors trust cached or initial-only decisions."},
  {"id": 70285, "domain": 1, "level": 3, "question": "A purpose of using a hardware security key with FIDO2 in identity architecture is to:", "options": ["Provide phishing-resistant authentication that is cryptographically bound to the real origin", "Store the user's plaintext account password directly for convenient automatic form filling in this enterprise environment", "Replace entirely the need for any server-side account management of the users involved", "Allow the same key to transparently authenticate the user to convincing phishing sites"], "correct": 0, "explanation": "FIDO2 keys are phishing-resistant via origin binding; the distractors describe password storage or phishing susceptibility."},
  {"id": 70286, "domain": 1, "level": 3, "question": "Why is it valuable to architect for centralized policy enforcement points?", "options": ["Letting each individual system enforce its own ad hoc policy is what ensures consistency", "Consistent enforcement avoids the gaps that arise when each system decides on its own", "Centralized enforcement conveniently removes the need for any policy definition at all", "Decentralized, undocumented enforcement actually scales better and is inherently safer"], "correct": 1, "explanation": "Central enforcement closes consistency gaps; the distractors describe fragmented or undefined enforcement."},
  {"id": 70287, "domain": 1, "level": 2, "question": "A reason to design network segmentation around data sensitivity is to:", "options": ["Place the most sensitive data onto the least restricted network segment for easy access", "Mix the sensitive and the public data freely together in order to simplify network design in this enterprise environment", "Confine the most sensitive data into tightly controlled and closely monitored secure zones", "Avoid monitoring any of the segments that happen to contain sensitive information at all"], "correct": 2, "explanation": "Sensitivity-based segmentation isolates crown jewels; the distractors expose or commingle sensitive data."},
  {"id": 70288, "domain": 1, "level": 2, "question": "Why is designing for token scope minimization with narrow OAuth scopes important?", "options": ["Broad scopes are actually safer because they reduce the total number of tokens issued", "The granted scope has no real effect on the damage that a stolen token could ever cause", "Maximum scope per token simplifies development without introducing any added risk at all", "A leaked token then grants only the limited access that matches its own narrow scope"], "correct": 3, "explanation": "Narrow scopes limit damage from a leaked token; the distractors favor broad scope or deny scope's impact."},
  {"id": 70289, "domain": 1, "level": 2, "question": "A purpose of architecting tamper-evident logging is to:", "options": ["Detect whether the logs have been altered or deleted at any point after an incident", "Allow administrators to silently edit the existing logs in order to fix their mistakes", "Ensure the logs can be freely overwritten as needed in order to save on storage space", "Encrypt the logs so that no one at all, including investigators, can ever read them"], "correct": 0, "explanation": "Tamper-evident logging reveals alteration or deletion; the distractors allow silent edits, overwrites, or block investigation."},
  {"id": 70290, "domain": 1, "level": 2, "question": "Why is designing for service-to-service authorization, not just authentication, important?", "options": ["Authentication of a service by itself automatically authorizes every one of its actions", "Knowing who a service is differs from deciding precisely what it is allowed to actually do", "Authorization becomes entirely unnecessary once two services have authenticated to each other", "Services should simply be allowed to take any action at all once their identity is proven"], "correct": 1, "explanation": "Authentication identifies, while authorization constrains actions; both are needed and the distractors conflate them."},
  {"id": 70291, "domain": 1, "level": 2, "question": "A reason to architect for immutable audit trails in regulated systems is to:", "options": ["Allow privileged users to rewrite history so that it matches their own desired outcomes", "Keep the audit data only on endpoints where it can later be wiped quickly and easily", "Provide reliable evidence that survives any deliberate attempts to later cover tracks", "Disable all of the audit logging during sensitive operations for performance reasons"], "correct": 2, "explanation": "Immutable audit trails preserve evidence against tampering; the distractors enable rewriting, wiping, or disabling logs."},
  {"id": 70292, "domain": 1, "level": 2, "question": "Why is designing explicit deny-by-default IAM policies recommended in the cloud?", "options": ["Everything remains permitted unless an explicit deny statement is later somehow discovered in this enterprise environment", "Deny-by-default conveniently removes the need to define any allow statements whatsoever", "Broad allow-all policies are actually easier to audit and are therefore inherently safer", "Access is then granted only where it is intentionally specified, limiting accidental exposure"], "correct": 3, "explanation": "Deny-by-default grants only intended access; allow-all and reactive denies expand exposure."},
  {"id": 70293, "domain": 1, "level": 2, "question": "A purpose of using separate encryption keys per tenant in multi-tenant SaaS is to:", "options": ["Limit the blast radius so one tenant's key compromise cannot expose the other tenants", "Share a single common key across all tenants purely to simplify the key rotation tasks", "Store every tenant's data fully unencrypted purely in order to improve query performance", "Allow any tenant to decrypt another tenant's data whenever they happen to need to do so"], "correct": 0, "explanation": "Per-tenant keys isolate compromise; shared keys, no encryption, and cross-tenant decryption break isolation."},
  {"id": 70294, "domain": 1, "level": 2, "question": "Why is designing for secure default network ACLs in cloud subnets important?", "options": ["Open defaults are clearly preferable so that new resources work without any setup at all", "Restrictive defaults prevent unintended exposure even if a resource is later misconfigured", "Network ACLs play no role whatsoever once a security group has been properly configured", "Default ACLs should always allow all traffic in order to reduce the volume of support tickets"], "correct": 1, "explanation": "Restrictive default ACLs catch misconfigurations; the distractors favor open defaults or dismiss layered controls."},
  {"id": 70295, "domain": 1, "level": 2, "question": "A reason to architect for workload identity instead of shared keys in cloud is that:", "options": ["All of the workloads share one key so that a single revocation affects everything at once", "Workload identities simply cannot be scoped and so must always carry full broad access", "Each workload receives a distinct, auditable identity with its own scoped permission set", "Shared static keys are actually far easier to rotate than per-workload distinct identities"], "correct": 2, "explanation": "Workload identity gives distinct, scoped, auditable access; shared keys broaden blast radius and complicate revocation."},
  {"id": 70296, "domain": 1, "level": 2, "question": "Why is it important to design for secure inter-region replication of data?", "options": ["Replication links can safely be left unencrypted because they are provider-internal anyway", "Replicated copies need no access control at all since they are merely exact duplicates", "Inter-region replication conveniently removes the need to secure the original primary copy", "Replicated data that crosses regions must remain encrypted and properly access-controlled"], "correct": 3, "explanation": "Replication must preserve encryption and access control; the distractors leave replicas or links unprotected."},
  {"id": 70297, "domain": 1, "level": 2, "question": "A purpose of designing clear separation between authentication and session management is to:", "options": ["Limit how a flaw in one mechanism can undermine the entire system's access control model", "Combine the two into one component so that a single bug then affects absolutely everything", "Ensure that user sessions never expire at all once the authentication succeeds even once", "Allow the session tokens to also double as the long-term authentication secrets themselves"], "correct": 0, "explanation": "Separating authentication and session management contains flaws; the distractors couple them or create long-lived risk."},
  {"id": 70298, "domain": 1, "level": 2, "question": "Why is designing for least-functionality container images such as distroless beneficial?", "options": ["Including every possible tool inside makes the resulting image far easier to attack safely", "Fewer included packages mean a smaller attack surface and correspondingly fewer vulnerabilities", "Larger container images are inherently more secure simply due to their built-in redundancy", "Distroless images simply cannot run any application and exist purely for decorative purposes in this enterprise environment"], "correct": 1, "explanation": "Minimal images reduce attack surface; the distractors favor bloat or misstate distroless capability."},
  {"id": 70299, "domain": 1, "level": 2, "question": "A reason to architect explicit trust zones for OT versus IT is that:", "options": ["OT and IT are entirely identical and so should share one single undifferentiated network in this enterprise environment", "OT systems are always inherently more secure and so need no isolation from IT at all", "OT and IT have different risk profiles that require distinct controls and clear isolation", "Combining OT and IT together neatly simplifies security with one universal shared policy"], "correct": 2, "explanation": "Distinct OT and IT zones reflect different risk profiles; the distractors flatten or misjudge OT requirements."},
  {"id": 70300, "domain": 1, "level": 2, "question": "Why is designing for secure key escrow and recovery important in encryption architecture?", "options": ["It allows literally anyone to recover any key at all without any authorization checks", "Escrow renders the encryption entirely worthless by exposing all of the keys publicly", "Recovery mechanisms should be wholly undocumented and known to absolutely no one at all in this enterprise environment", "It balances strong encryption against the ability to recover the data legitimately later"], "correct": 3, "explanation": "Controlled escrow enables legitimate recovery without undermining encryption; the distractors describe open or absent recovery."}
];
